export interface UserSession {
  username: string;
  isLoggedIn: boolean;
  progress: number;
  quizScores: number[];
  joinedAt: string;
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  type: 'MCQ' | 'TF' | 'IMAGE';
  imageUrl?: string;
}

export interface EvidenceType {
  id: string;
  name: string;
  category: string;
  toolsNeeded: string[];
  packaging: string;
  storage: string;
  temperature: string;
  description: string;
}

export interface CaseStudy {
  id: string;
  title: string;
  category: string;
  description: string;
  techniquesUsed: string[];
  outcome: string;
  color: string;
  subtext: string;
  sourceUrl?: string;
  relatedCaseIds?: string[];
}

export interface LabDivision {
  id: string;
  name: string;
  description: string;
  subFields: string[];
}

export type TabType = 'home' | 'evidence' | 'sketch' | 'lab' | 'library' | 'exams' | 'profile' | 'expert';

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface PathPoint {
  x: number;
  y: number;
}

export interface SceneObject {
  id: string;
  type: 'Marker' | 'Wall' | 'Furniture' | 'Path' | 'Label';
  subType: string;
  label: string;
  x: number;
  y: number;
  width: number;
  depth: number;
  rotation: number;
  color: string;
  points?: PathPoint[]; // For walls and paths
  evidenceId?: string; // e.g., "E1", "E2"
}

export interface RoomDimensions {
  width: number;
  length: number;
}

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Undo2, 
  Redo2, 
  Save, 
  MousePointer2, 
  Move,
  Activity,
  Square,
  Minus,
  Type as TypeIcon,
  Download,
  FileText
} from 'lucide-react';
import { SceneObject, RoomDimensions, PathPoint } from '../types';

const EVIDENCE_MARKERS = [
  { subType: 'Body', icon: '👤', label: 'E1: Body' },
  { subType: 'Firearm', icon: '🔫', label: 'E2: Weapon' },
  { subType: 'Blood', icon: '🩸', label: 'E3: Blood' },
  { subType: 'Footprints', icon: '👣', label: 'E4: Footprints' },
  { subType: 'Forced Entry', icon: '🔨', label: 'E5: Entry' },
  { subType: 'Broken Glass', icon: '💎', label: 'E6: Glass' }
];

const ARCHITECTURAL_ITEMS = [
  { subType: 'Wall', label: 'Wall Segment' },
  { subType: 'Bed', label: 'Furniture: Bed' },
  { subType: 'Toilet', label: 'Furniture: Toilet' },
  { subType: 'Door', label: 'Entrance' },
  { subType: 'Window', label: 'Window' }
];

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 20, length: 15 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [history, setHistory] = useState<SceneObject[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [mode, setMode] = useState<'Select' | 'Wall' | 'Path'>('Select');

  const [caseInfo, setCaseInfo] = useState({
    caseNo: 'FN-2024-102',
    investigator: 'Investigator Doe',
    date: new Date().toLocaleDateString()
  });

  const pixelsPerMeter = 40;
  const padding = 80;

  const pushToHistory = useCallback((newObjects: SceneObject[]) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newObjects)));
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_pro');
    if (saved) {
      const data = JSON.parse(saved);
      setObjects(data.objects);
      setRoom(data.room || { width: 20, length: 15 });
      pushToHistory(data.objects);
    } else {
      // Default Template
      const initial: SceneObject[] = [
        { id: '1', type: 'Marker', subType: 'Body', label: 'E1', x: 14, y: 5, width: 2, depth: 4, rotation: 30, color: '#ef4444', evidenceId: 'E1' },
        { id: '2', type: 'Marker', subType: 'Firearm', label: 'E2', x: 16, y: 8, width: 0.5, depth: 0.5, rotation: -45, color: '#334155', evidenceId: 'E2' },
        { id: '3', type: 'Marker', subType: 'Blood', label: 'E3', x: 13, y: 6, width: 1.5, depth: 1.5, rotation: 0, color: '#b91c1c', evidenceId: 'E3' },
      ];
      setObjects(initial);
      pushToHistory(initial);
    }
  }, []);

  useEffect(() => {
    draw();
  }, [room, objects, selectedId, caseInfo]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 3; // Extra space for footer
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;
    const floorW = room.width * pixelsPerMeter;
    const floorH = room.length * pixelsPerMeter;

    // 1. Background Grid (Architectural Style)
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= room.width; x++) {
      ctx.beginPath();
      ctx.moveTo(startX + x * pixelsPerMeter, startY);
      ctx.lineTo(startX + x * pixelsPerMeter, startY + floorH);
      ctx.stroke();
    }
    for (let y = 0; y <= room.length; y++) {
      ctx.beginPath();
      ctx.moveTo(startX, startY + y * pixelsPerMeter);
      ctx.lineTo(startX + floorW, startY + y * pixelsPerMeter);
      ctx.stroke();
    }

    // 2. Title
    ctx.fillStyle = '#000000';
    ctx.font = 'bold 20px Inter';
    ctx.textAlign = 'left';
    ctx.fillText('Homicide Crime Scene Investigation Diagram', startX, startY - 30);

    // 3. Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Selection Highlight
      if (selectedId === obj.id) {
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        ctx.strokeRect(-drawW/2 - 5, -drawD/2 - 5, drawW + 10, drawD + 10);
        ctx.setLineDash([]);
      }

      if (obj.subType === 'Body') {
        // Body Outline
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW/2.5, drawD/2.5, 0, 0, Math.PI * 2);
        ctx.stroke();
        // Limbs sketch
        ctx.moveTo(-drawW/4, -drawD/3); ctx.lineTo(-drawW/2, -drawD/2);
        ctx.moveTo(drawW/4, -drawD/3); ctx.lineTo(drawW/2, -drawD/2);
        ctx.moveTo(-drawW/4, drawD/3); ctx.lineTo(-drawW/2, drawD/2);
        ctx.moveTo(drawW/4, drawD/3); ctx.lineTo(drawW/2, drawD/2);
        ctx.stroke();
      } else if (obj.subType === 'Firearm') {
        ctx.fillStyle = '#334';
        ctx.fillRect(-drawW/2, -drawD/4, drawW, drawD/2);
        ctx.fillRect(-drawW/2, -drawD/2, drawW/4, drawD);
      } else if (obj.subType === 'Blood') {
        ctx.fillStyle = '#b91c1c';
        ctx.beginPath();
        for(let i=0; i<8; i++) {
          const angle = (i/8) * Math.PI * 2;
          const r = (drawW/2) * (0.6 + Math.random() * 0.4);
          ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.fill();
      } else if (obj.subType === 'Wall') {
        ctx.fillStyle = '#000';
        ctx.fillRect(-drawW/2, -drawD/2, drawW, drawD);
      } else if (obj.subType === 'Bed') {
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 1.5;
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
        ctx.strokeRect(-drawW/2 + 5, -drawD/2 + 5, drawW - 10, drawD/3); // Pillows
      } else if (obj.subType === 'Footprints') {
        ctx.fillStyle = '#666';
        ctx.beginPath();
        ctx.ellipse(-5, 0, 3, 6, 0.2, 0, Math.PI*2);
        ctx.ellipse(5, 10, 3, 6, -0.2, 0, Math.PI*2);
        ctx.fill();
      } else {
        ctx.strokeStyle = '#000';
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
      }

      // Evidence Callout (Circle with dotted line)
      if (obj.evidenceId) {
        ctx.restore();
        ctx.save();
        ctx.translate(startX + obj.x * pixelsPerMeter, startY + obj.y * pixelsPerMeter);

        // Offset callout
        const calloutX = 120;
        const calloutY = -60;

        ctx.beginPath();
        ctx.setLineDash([5, 5]);
        ctx.strokeStyle = '#000';
        ctx.moveTo(0, 0);
        ctx.lineTo(calloutX, calloutY);
        ctx.stroke();
        ctx.setLineDash([]);

        ctx.beginPath();
        ctx.arc(calloutX, calloutY, 25, 0, Math.PI * 2);
        ctx.fillStyle = '#fff';
        ctx.fill();
        ctx.stroke();

        ctx.fillStyle = '#000';
        ctx.font = 'bold 14px Inter';
        ctx.textAlign = 'center';
        ctx.fillText(obj.evidenceId, calloutX, calloutY - 5);
        ctx.font = '10px Inter';
        ctx.fillText(obj.subType.toLowerCase(), calloutX, calloutY + 12);
      }

      ctx.restore();
    });

    // 4. Draw Footer Table
    const footerY = startY + floorH + 40;
    ctx.strokeStyle = '#000';
    ctx.lineWidth = 1;
    ctx.strokeRect(startX + floorW * 0.4, footerY, floorW * 0.6, 50);

    // Table dividers
    ctx.beginPath();
    ctx.moveTo(startX + floorW * 0.6, footerY);
    ctx.lineTo(startX + floorW * 0.6, footerY + 50);
    ctx.moveTo(startX + floorW * 0.8, footerY);
    ctx.lineTo(startX + floorW * 0.8, footerY + 50);
    ctx.stroke();

    ctx.fillStyle = '#000';
    ctx.font = 'bold 11px Inter';
    ctx.fillText('Case #', startX + floorW * 0.4 + 5, footerY + 15);
    ctx.fillText('Investigator', startX + floorW * 0.6 + 5, footerY + 15);
    ctx.fillText('Date:', startX + floorW * 0.8 + 5, footerY + 15);

    ctx.font = '12px Courier';
    ctx.fillText(caseInfo.caseNo, startX + floorW * 0.4 + 5, footerY + 35);
    ctx.fillText(caseInfo.investigator, startX + floorW * 0.6 + 5, footerY + 35);
    ctx.fillText(caseInfo.date, startX + floorW * 0.8 + 5, footerY + 35);
  };

  const addObject = (subType: string, type: 'Marker' | 'Furniture' | 'Wall' = 'Marker') => {
    const isMarker = type === 'Marker';
    const newObject: SceneObject = {
      id: Date.now().toString(),
      type: type,
      subType: subType,
      label: subType,
      x: room.width / 2,
      y: room.length / 2,
      width: isMarker ? 1 : 4,
      depth: isMarker ? 1 : 2,
      rotation: 0,
      color: '#000',
      evidenceId: isMarker ? `E${objects.filter(o => o.type === 'Marker').length + 1}` : undefined
    };
    const newObjects = [...objects, newObject];
    setObjects(newObjects);
    pushToHistory(newObjects);
    setSelectedId(newObject.id);
  };

  const removeSelected = () => {
    if (!selectedId) return;
    const newObjects = objects.filter(o => o.id !== selectedId);
    setObjects(newObjects);
    pushToHistory(newObjects);
    setSelectedId(null);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    setObjects(prev => prev.map(obj => 
      obj.id === selectedId 
        ? { ...obj, x: Math.round((mouseX - dragOffset.x) * 2) / 2, y: Math.round((mouseY - dragOffset.y) * 2) / 2 } 
        : obj
    ));
  };

  const handleMouseUp = () => {
    if (isDragging) {
      setIsDragging(false);
      pushToHistory(objects);
    }
  };

  const saveProject = () => {
    localStorage.setItem('forenova_sketch_pro', JSON.stringify({ objects, room }));
    alert("Diagram saved to local database.");
  };

  return (
    <div className="flex flex-col gap-6 h-full">
      {/* Toolbar */}
      <div className="flex flex-wrap items-center justify-between bg-slate-900 border border-slate-800 p-4 rounded-2xl">
        <div className="flex items-center gap-2">
          <button 
            onClick={() => setMode('Select')}
            className={`p-2 rounded-lg transition-all ${mode === 'Select' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}
          >
            <MousePointer2 size={20} />
          </button>
          <div className="w-px h-6 bg-slate-800 mx-2" />
          <button onClick={() => pushToHistory(objects)} className="p-2 text-slate-400 hover:bg-slate-800 rounded-lg"><Undo2 size={18} /></button>
          <button onClick={() => setHistoryIndex(historyIndex + 1)} className="p-2 text-slate-400 hover:bg-slate-800 rounded-lg"><Redo2 size={18} /></button>
          <div className="w-px h-6 bg-slate-800 mx-2" />
          <button onClick={saveProject} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-xl text-xs font-bold">
            <Save size={16} /> Save Diagram
          </button>
        </div>

        <div className="flex items-center gap-2">
           <div className="bg-slate-800 rounded-xl px-4 py-2 flex items-center gap-3">
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Grid Scale</span>
              <span className="text-xs font-mono text-blue-400">1m : 40px</span>
           </div>
           <button className="p-2 bg-slate-800 text-slate-400 rounded-xl hover:text-white transition-all">
              <Download size={20} />
           </button>
        </div>
      </div>

      <div className="grid grid-cols-12 gap-6 flex-1">
        {/* Left Control Panel */}
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-6 max-h-[calc(100vh-250px)] overflow-y-auto">

            {/* Case Info */}
            <div className="space-y-3">
              <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] mb-4">Diagram Meta</h3>
              <div className="space-y-2">
                <input 
                  type="text" value={caseInfo.caseNo} 
                  onChange={e => setCaseInfo({...caseInfo, caseNo: e.target.value})}
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-xs font-mono"
                  placeholder="Case Number"
                />
                <input 
                  type="text" value={caseInfo.investigator} 
                  onChange={e => setCaseInfo({...caseInfo, investigator: e.target.value})}
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-xs font-mono"
                  placeholder="Investigator"
                />
              </div>
            </div>

            {/* Markers */}
            <div className="space-y-3">
              <h3 className="text-[10px] font-bold text-blue-500 uppercase tracking-[0.2em] flex items-center gap-2">
                <Activity size={14} /> Evidence Markers
              </h3>
              <div className="grid grid-cols-2 gap-2">
                {EVIDENCE_MARKERS.map(m => (
                  <button 
                    key={m.subType}
                    onClick={() => addObject(m.subType, 'Marker')}
                    className="flex flex-col items-center justify-center p-3 bg-slate-800 hover:bg-blue-600/20 border border-transparent hover:border-blue-500 rounded-xl transition-all group"
                  >
                    <span className="text-xl group-hover:scale-125 transition-transform">{m.icon}</span>
                    <span className="text-[9px] font-bold mt-1 text-slate-400 group-hover:text-blue-400">{m.subType}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Architectural */}
            <div className="space-y-3">
              <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                <Square size={14} /> Architectural
              </h3>
              <div className="space-y-2">
                {ARCHITECTURAL_ITEMS.map(i => (
                  <button 
                    key={i.subType}
                    onClick={() => addObject(i.subType, i.subType === 'Wall' ? 'Wall' : 'Furniture')}
                    className="w-full flex items-center gap-3 p-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-left text-xs font-medium"
                  >
                    <div className="w-6 h-6 bg-slate-900 rounded flex items-center justify-center">
                      {i.subType === 'Wall' ? <Minus size={14} /> : i.subType === 'Door' ? <Activity size={14} /> : <Square size={14} />}
                    </div>
                    {i.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Selected Object Controls */}
            {selectedId && (
              <div className="pt-6 border-t border-slate-800 space-y-4 animate-in fade-in">
                <div className="flex items-center justify-between">
                  <h3 className="text-[10px] font-bold text-amber-500 uppercase tracking-widest">Adjust Selection</h3>
                  <button onClick={removeSelected} className="text-rose-500 hover:bg-rose-500/10 p-2 rounded-lg"><Trash2 size={16} /></button>
                </div>
                <div className="space-y-4">
                  <div>
                    <div className="flex justify-between text-[10px] text-slate-500 mb-1 font-bold">
                      <span>Rotation</span>
                      <span>{objects.find(o => o.id === selectedId)?.rotation}°</span>
                    </div>
                    <input 
                      type="range" min="0" max="360" step="5"
                      value={objects.find(o => o.id === selectedId)?.rotation || 0}
                      onChange={e => setObjects(prev => prev.map(o => o.id === selectedId ? {...o, rotation: Number(e.target.value)} : o))}
                      className="w-full accent-blue-500"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1">
                      <label className="text-[9px] text-slate-500 font-bold">Width (m)</label>
                      <input 
                        type="number" step="0.1"
                        value={objects.find(o => o.id === selectedId)?.width || 1}
                        onChange={e => setObjects(prev => prev.map(o => o.id === selectedId ? {...o, width: Number(e.target.value)} : o))}
                        className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-xs font-mono"
                      />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] text-slate-500 font-bold">Depth (m)</label>
                      <input 
                        type="number" step="0.1"
                        value={objects.find(o => o.id === selectedId)?.depth || 1}
                        onChange={e => setObjects(prev => prev.map(o => o.id === selectedId ? {...o, depth: Number(e.target.value)} : o))}
                        className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-xs font-mono"
                      />
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Drawing Area */}
        <div className="col-span-12 lg:col-span-9 bg-slate-950 border border-slate-800 rounded-2xl relative overflow-auto shadow-inner flex items-center justify-center min-h-[600px]">
           <canvas
             ref={canvasRef}
             onMouseDown={handleMouseDown}
             onMouseMove={handleMouseMove}
             onMouseUp={handleMouseUp}
             onMouseLeave={handleMouseUp}
             className="bg-white shadow-2xl cursor-crosshair m-10"
           />

           {/* Interactive Overlay Overlay */}
           <div className="absolute top-4 right-4 flex flex-col gap-2">
              <div className="bg-white/10 backdrop-blur-md p-3 rounded-2xl border border-white/10 text-[10px] text-white/50 font-mono">
                 <p>SCENE DIMENSIONS</p>
                 <p className="text-white font-bold">{room.width}m x {room.length}m</p>
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default SketchTool;

export interface UserSession {
  username: string;
  isLoggedIn: boolean;
  progress: number;
  quizScores: number[];
  joinedAt: string;
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  type: 'MCQ' | 'TF' | 'IMAGE';
  imageUrl?: string;
}

export interface EvidenceType {
  id: string;
  name: string;
  category: string;
  toolsNeeded: string[];
  packaging: string;
  storage: string;
  temperature: string;
  description: string;
}

export interface CaseStudy {
  id: string;
  title: string;
  category: string;
  description: string;
  techniquesUsed: string[];
  outcome: string;
  findings: string[]; // New: Detailed forensic findings
  color: string;
  subtext: string; // Used as the primary findings label on card
  sourceUrl?: string;
  relatedCaseIds?: string[];
}

export interface LabDivision {
  id: string;
  name: string;
  description: string;
  subFields: string[];
}

export type TabType = 'home' | 'evidence' | 'sketch' | 'lab' | 'library' | 'exams' | 'profile' | 'expert';

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface PathPoint {
  x: number;
  y: number;
}

export interface SceneObject {
  id: string;
  type: 'Marker' | 'Wall' | 'Furniture' | 'Path' | 'Label';
  subType: string;
  label: string;
  x: number;
  y: number;
  width: number;
  depth: number;
  rotation: number;
  color: string;
  points?: PathPoint[];
  evidenceId?: string;
}

export interface RoomDimensions {
  width: number;
  length: number;
}

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Undo2, 
  Redo2, 
  Save, 
  MousePointer2, 
  Activity,
  Square,
  Minus,
  Download,
  Sparkles,
  ArrowRight,
  Maximize2
} from 'lucide-react';
import { SceneObject, RoomDimensions, PathPoint } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

const EVIDENCE_MARKERS = [
  { subType: 'Body', icon: '👤', label: 'E1: Body' },
  { subType: 'Firearm', icon: '🔫', label: 'E2: Weapon' },
  { subType: 'Blood', icon: '🩸', label: 'E3: Blood' },
  { subType: 'Footprints', icon: '👣', label: 'E4: Footprints' },
  { subType: 'Forced Entry', icon: '🔨', label: 'E5: Entry' },
  { subType: 'Broken Glass', icon: '💎', label: 'E6: Glass' }
];

const ARCHITECTURAL_ITEMS = [
  { subType: 'Wall', label: 'Wall Segment' },
  { subType: 'Bed', label: 'Furniture: Bed' },
  { subType: 'Toilet', label: 'Furniture: Toilet' },
  { subType: 'Door', label: 'Entrance' },
  { subType: 'Window', label: 'Window' }
];

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 20, length: 15 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [history, setHistory] = useState<SceneObject[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [mode, setMode] = useState<'Select' | 'Wall' | 'Path'>('Select');
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [caseInfo, setCaseInfo] = useState({
    caseNo: 'FN-2024-102',
    investigator: 'Investigator Doe',
    date: new Date().toLocaleDateString()
  });

  const pixelsPerMeter = 40;
  const padding = 80;

  const pushToHistory = useCallback((newObjects: SceneObject[]) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(JSON.parse(JSON.stringify(newObjects)));
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_pro');
    if (saved) {
      const data = JSON.parse(saved);
      setObjects(data.objects);
      setRoom(data.room || { width: 20, length: 15 });
      pushToHistory(data.objects);
    } else {
      const initial: SceneObject[] = [
        { id: '1', type: 'Marker', subType: 'Body', label: 'E1', x: 10, y: 7.5, width: 2, depth: 4, rotation: 30, color: '#ef4444', evidenceId: 'E1' },
      ];
      setObjects(initial);
      pushToHistory(initial);
    }
  }, []);

  useEffect(() => {
    draw();
  }, [room, objects, selectedId, caseInfo]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 3;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;
    const floorW = room.width * pixelsPerMeter;
    const floorH = room.length * pixelsPerMeter;

    // 1. Grid
    ctx.strokeStyle = '#f1f5f9';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= room.width; x++) {
      ctx.beginPath();
      ctx.moveTo(startX + x * pixelsPerMeter, startY);
      ctx.lineTo(startX + x * pixelsPerMeter, startY + floorH);
      ctx.stroke();
    }
    for (let y = 0; y <= room.length; y++) {
      ctx.beginPath();
      ctx.moveTo(startX, startY + y * pixelsPerMeter);
      ctx.lineTo(startX + floorW, startY + y * pixelsPerMeter);
      ctx.stroke();
    }

    // 2. Room Border & Measurements
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 2;
    ctx.strokeRect(startX, startY, floorW, floorH);

    // Dimension Lines
    ctx.fillStyle = '#64748b';
    ctx.font = 'bold 12px JetBrains Mono';
    ctx.textAlign = 'center';

    // Top Width Measurement
    ctx.fillText(`${room.width.toFixed(1)}m`, startX + floorW / 2, startY - 10);
    ctx.beginPath();
    ctx.moveTo(startX, startY - 15); ctx.lineTo(startX + floorW, startY - 15);
    ctx.stroke();

    // Left Length Measurement
    ctx.save();
    ctx.translate(startX - 15, startY + floorH / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText(`${room.length.toFixed(1)}m`, 0, 0);
    ctx.restore();

    // 3. Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      if (selectedId === obj.id) {
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        ctx.strokeRect(-drawW/2 - 5, -drawD/2 - 5, drawW + 10, drawD + 10);
        ctx.setLineDash([]);
      }

      ctx.strokeStyle = '#000';
      ctx.lineWidth = 1.5;

      if (obj.subType === 'Body') {
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW/2.5, drawD/2.5, 0, 0, Math.PI * 2);
        ctx.stroke();
      } else if (obj.subType === 'Firearm') {
        ctx.fillStyle = '#334';
        ctx.fillRect(-drawW/2, -drawD/4, drawW, drawD/2);
      } else if (obj.subType === 'Blood') {
        ctx.fillStyle = '#b91c1c';
        ctx.beginPath();
        for(let i=0; i<8; i++) {
          const angle = (i/8) * Math.PI * 2;
          const r = (drawW/2) * (0.6 + Math.random() * 0.4);
          ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.fill();
      } else if (obj.subType === 'Bed') {
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
        ctx.strokeRect(-drawW/2 + 5, -drawD/2 + 5, drawW - 10, drawD/3);
      } else {
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
      }

      if (obj.evidenceId) {
        ctx.restore();
        ctx.save();
        ctx.translate(startX + obj.x * pixelsPerMeter, startY + obj.y * pixelsPerMeter);
        const calloutX = 80;
        const calloutY = -50;
        ctx.beginPath();
        ctx.setLineDash([2, 2]);
        ctx.moveTo(0, 0); ctx.lineTo(calloutX, calloutY);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.beginPath();
        ctx.arc(calloutX, calloutY, 20, 0, Math.PI * 2);
        ctx.fillStyle = '#fff'; ctx.fill(); ctx.stroke();
        ctx.fillStyle = '#000'; ctx.font = 'bold 12px Inter'; ctx.textAlign = 'center';
        ctx.fillText(obj.evidenceId, calloutX, calloutY + 5);
      }

      ctx.restore();
    });

    // 4. Footer Table
    const footerY = startY + floorH + 60;
    ctx.strokeRect(startX, footerY, floorW, 50);
    ctx.beginPath(); ctx.moveTo(startX + floorW * 0.33, footerY); ctx.lineTo(startX + floorW * 0.33, footerY + 50); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(startX + floorW * 0.66, footerY); ctx.lineTo(startX + floorW * 0.66, footerY + 50); ctx.stroke();

    ctx.fillStyle = '#000'; ctx.font = 'bold 10px Inter';
    ctx.fillText('CASE: ' + caseInfo.caseNo, startX + 10, footerY + 30);
    ctx.fillText('INVESTIGATOR: ' + caseInfo.investigator, startX + floorW * 0.33 + 10, footerY + 30);
    ctx.fillText('DATE: ' + caseInfo.date, startX + floorW * 0.66 + 10, footerY + 30);
  };

  const generateSceneWithAI = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `Generate a forensic scene layout JSON for the prompt: "${prompt}".
        Output strictly in JSON format with "room" (width, length in meters) and "objects" array.
        Object keys: id, subType (must be from: Body, Firearm, Blood, Footprints, Forced Entry, Broken Glass, Bed, Door, Window, Table), x, y, width, depth, rotation, evidenceId (if applicable like E1, E2).
        Keep room size around 10-20m.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              room: {
                type: Type.OBJECT,
                properties: {
                  width: { type: Type.NUMBER },
                  length: { type: Type.NUMBER }
                },
                required: ['width', 'length']
              },
              objects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    subType: { type: Type.STRING },
                    x: { type: Type.NUMBER },
                    y: { type: Type.NUMBER },
                    width: { type: Type.NUMBER },
                    depth: { type: Type.NUMBER },
                    rotation: { type: Type.NUMBER },
                    evidenceId: { type: Type.STRING }
                  }
                }
              }
            }
          }
        }
      });

      const result = JSON.parse(response.text);
      setRoom(result.room);
      setObjects(result.objects.map((o: any, i: number) => ({
        ...o,
        id: `ai-${i}`,
        type: o.subType === 'Bed' || o.subType === 'Table' ? 'Furniture' : 'Marker'
      })));
      pushToHistory(result.objects);
    } catch (error) {
      console.error("AI Generation Error:", error);
      alert("Failed to generate scene. Try a simpler prompt.");
    } finally {
      setIsGenerating(false);
    }
  };

  const addObject = (subType: string, type: 'Marker' | 'Furniture' | 'Wall' = 'Marker') => {
    const isMarker = type === 'Marker';
    const newObject: SceneObject = {
      id: Date.now().toString(),
      type: type,
      subType: subType,
      label: subType,
      x: room.width / 2,
      y: room.length / 2,
      width: isMarker ? 1 : 4,
      depth: isMarker ? 1 : 2,
      rotation: 0,
      color: '#000',
      evidenceId: isMarker ? `E${objects.filter(o => o.type === 'Marker').length + 1}` : undefined
    };
    const newObjects = [...objects, newObject];
    setObjects(newObjects);
    pushToHistory(newObjects);
    setSelectedId(newObject.id);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;
    setObjects(prev => prev.map(obj => obj.id === selectedId ? { ...obj, x: Math.round(mouseX * 2) / 2, y: Math.round(mouseY * 2) / 2 } : obj));
  };

  return (
    <div className="flex flex-col gap-6 h-full">
      {/* Edraw Style Agent Bar */}
      <div className="relative overflow-hidden bg-gradient-to-r from-slate-900 via-indigo-950 to-slate-900 border border-slate-800 p-6 rounded-3xl shadow-2xl">
        <div className="flex items-center gap-6 relative z-10">
          <div className="bg-white/10 p-4 rounded-2xl backdrop-blur-md ring-1 ring-white/20">
            <Sparkles className="text-blue-400 animate-pulse" size={32} />
          </div>
          <div className="flex-1 space-y-2">
             <div className="flex items-center justify-between">
                <h2 className="text-white font-bold text-lg flex items-center gap-2">
                   ForeNova Agent <span className="bg-blue-600 px-2 py-0.5 rounded text-[8px] uppercase tracking-widest">v2.0</span>
                </h2>
                {isGenerating && <span className="text-[10px] text-blue-400 animate-pulse font-mono tracking-widest uppercase">Generating Scene Data...</span>}
             </div>
             <div className="relative group">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && generateSceneWithAI()}
                  placeholder="Describe your scene (e.g., 'Small office crime scene with blood by the desk')..."
                  className="w-full bg-black/40 border border-white/10 rounded-2xl py-4 pl-6 pr-32 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all placeholder:text-slate-600"
                />
                <button 
                  onClick={generateSceneWithAI}
                  disabled={isGenerating || !prompt.trim()}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white px-6 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-500/20"
                >
                  Generate <ArrowRight size={18} />
                </button>
             </div>
          </div>
        </div>
        <div className="absolute top-0 right-0 p-2 opacity-5 pointer-events-none">
          <Maximize2 size={120} className="rotate-12" />
        </div>
      </div>

      <div className="grid grid-cols-12 gap-6 flex-1">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 space-y-6 max-h-[calc(100vh-400px)] overflow-y-auto">
             <div className="space-y-4">
                <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Standard Assets</h3>
                <div className="grid grid-cols-2 gap-2">
                  {EVIDENCE_MARKERS.map(m => (
                    <button key={m.subType} onClick={() => addObject(m.subType)} className="flex flex-col items-center p-3 bg-slate-800 hover:bg-slate-700 rounded-xl transition-all">
                      <span className="text-xl">{m.icon}</span>
                      <span className="text-[9px] font-bold mt-1">{m.subType}</span>
                    </button>
                  ))}
                </div>
             </div>
             <div className="pt-4 border-t border-slate-800">
                <button onClick={() => setRoom(prev => ({ ...prev, width: prev.width + 1 }))} className="w-full text-xs bg-slate-800 hover:bg-slate-700 p-2 rounded-lg text-slate-400 mb-2">+ Room Width</button>
                <button onClick={() => setRoom(prev => ({ ...prev, length: prev.length + 1 }))} className="w-full text-xs bg-slate-800 hover:bg-slate-700 p-2 rounded-lg text-slate-400">+ Room Length</button>
             </div>
          </div>
        </div>

        <div className="col-span-12 lg:col-span-9 bg-slate-950 border border-slate-800 rounded-2xl relative overflow-auto shadow-inner flex items-center justify-center min-h-[500px]">
           <canvas
             ref={canvasRef}
             onMouseDown={handleMouseDown}
             onMouseMove={handleMouseMove}
             onMouseUp={() => setIsDragging(false)}
             className="bg-white shadow-2xl cursor-crosshair m-10"
           />
        </div>
      </div>
    </div>
  );
};

export default SketchTool;

