                       <p className="text-sm text-indigo-100/70 leading-relaxed">
                          ForeNova Labs leverage the latest standardized methods as defined by SWG (Scientific Working Groups) globally. 
                          Our current protocols for {activeDivision.subFields[0]} utilize NIST-certified reference standards to ensure courtroom admissibility.
                       </p>
                       <button className="flex items-center gap-2 text-xs font-bold text-indigo-400 hover:text-white transition-colors">
                          EXPLORE CASE STUDIES <ArrowRight size={14} />
                       </button>
                    </div>
                 </div>
                 <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none rotate-12 group-hover:rotate-45 transition-transform duration-700">
                    <Beaker size={140} />
                 </div>
              </div>
            </div>
          )}

          {mode === 'simulation' && (
            <div className="bg-slate-950 border border-slate-800 rounded-3xl h-full min-h-[500px] flex flex-col animate-in zoom-in duration-300 overflow-hidden">
               <div className="bg-slate-900 p-6 border-b border-slate-800 flex justify-between items-center">
                  <div>
                    <h3 className="text-lg font-bold">Virtual Lab Simulation</h3>
                    <p className="text-[10px] text-blue-500 font-bold uppercase tracking-widest">Protocol: {activeDivision.name}</p>
                  </div>
                  <div className="flex gap-1">
                    {activeDivision.procedure.map(p => (
                      <div key={p.step} className={`w-8 h-1 rounded-full ${p.step <= simStep ? 'bg-blue-500' : 'bg-slate-800'}`}></div>
                    ))}
                  </div>
               </div>

               <div className="flex-1 p-8 flex flex-col items-center justify-center text-center space-y-6 relative">
                  <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center ring-8 ring-blue-600/5 border border-blue-500/20">
                     <Play size={40} className="text-blue-500" />
                  </div>
                  <div className="max-w-md space-y-4">
                     <h4 className="text-xl font-bold text-white">{activeDivision.procedure[simStep - 1]?.title}</h4>
                     <p className="text-slate-400 leading-relaxed">
                        {activeDivision.procedure[simStep - 1]?.action}
                     </p>
                  </div>

                  <div className="absolute bottom-8 left-8 right-8 flex justify-between items-center">
                     <button 
                        disabled={simStep === 1}
                        onClick={() => setSimStep(prev => prev - 1)}
                        className="px-6 py-3 bg-slate-800 hover:bg-slate-700 disabled:opacity-30 rounded-2xl text-xs font-bold transition-all"
                     >
                        Previous Step
                     </button>
                     <button 
                        onClick={() => simStep < activeDivision.procedure.length ? setSimStep(prev => prev + 1) : setSimStep(1)}
                        className="px-8 py-3 bg-blue-600 hover:bg-blue-500 rounded-2xl text-xs font-bold shadow-xl shadow-blue-500/20 transition-all flex items-center gap-2"
                     >
                        {simStep === activeDivision.procedure.length ? 'Restart Protocol' : 'Execute Step'} <ChevronRight size={14} />
                     </button>
                  </div>
               </div>
            </div>
          )}

          {mode === 'quiz' && (
            <div className="bg-slate-900 border border-slate-800 rounded-3xl p-10 h-full flex flex-col animate-in slide-in-from-bottom-4 duration-300">
               {!quizState.finished ? (
                 <div className="space-y-8 flex-1 flex flex-col">
                    <div className="flex justify-between items-center">
                       <div className="flex items-center gap-3">
                          <div className="p-2 bg-blue-500/20 rounded-xl text-blue-500">
                             <ClipboardList size={20} />
                          </div>
                          <h3 className="font-bold text-white">Lab Proficiency Test</h3>
                       </div>
                       <span className="text-[10px] font-mono text-slate-500 font-bold">Q {quizState.idx + 1}/{activeDivision.quiz.length}</span>
                    </div>

                    <div className="space-y-6 flex-1">
                       <h4 className="text-xl font-bold leading-relaxed">{activeDivision.quiz[quizState.idx].question}</h4>

                       <div className="grid grid-cols-1 gap-3">
                          {activeDivision.quiz[quizState.idx].options.map((opt, i) => (
                             <button 
                                key={i}
                                disabled={quizState.answered}
                                onClick={() => handleAnswer(i)}
                                className={`p-5 rounded-2xl border-2 text-left transition-all flex justify-between items-center group ${
                                   quizState.answered
                                   ? i === activeDivision.quiz[quizState.idx].correctAnswer
                                      ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400'
                                      : i === quizState.selected
                                         ? 'bg-rose-500/10 border-rose-500 text-rose-400'
                                         : 'bg-slate-800 border-slate-700 opacity-40'
                                   : 'bg-slate-800 border-slate-700 hover:border-blue-500/50 hover:bg-slate-800'
                                }`}
                             >
                                <span className="font-bold text-sm">{opt}</span>
                                {quizState.answered && i === activeDivision.quiz[quizState.idx].correctAnswer && <CheckCircle2 size={18} />}
                                {quizState.answered && i === quizState.selected && i !== activeDivision.quiz[quizState.idx].correctAnswer && <XCircle size={18} />}
                             </button>
                          ))}
                       </div>

                       {quizState.answered && (
                         <div className="bg-blue-600/5 border border-blue-500/20 p-5 rounded-2xl flex items-start gap-3 animate-in fade-in duration-300">
                            <Info size={18} className="text-blue-500 shrink-0 mt-0.5" />
                            <p className="text-xs text-slate-400 leading-relaxed italic">{activeDivision.quiz[quizState.idx].explanation}</p>
                         </div>
                       )}
                    </div>

                    <button 
                       disabled={!quizState.answered}
                       onClick={nextQuestion}
                       className="w-full py-4 bg-blue-600 hover:bg-blue-700 disabled:opacity-30 rounded-2xl text-sm font-bold shadow-xl shadow-blue-500/20 transition-all flex items-center justify-center gap-2 mt-auto"
                    >
                       {quizState.idx === activeDivision.quiz.length - 1 ? 'See Results' : 'Continue'} <ArrowRight size={16} />
                    </button>
                 </div>
               ) : (
                 <div className="flex-1 flex flex-col items-center justify-center text-center space-y-8 animate-in zoom-in">
                    <div className="relative">
                       <div className="w-32 h-32 bg-emerald-500/10 rounded-full flex items-center justify-center ring-8 ring-emerald-500/5">
                          <ShieldCheck size={64} className="text-emerald-500" />
                       </div>
                    </div>
                    <div>
                       <h3 className="text-3xl font-bold text-white">Proficiency Certified</h3>
                       <p className="text-slate-400 mt-2">You achieved a score of {quizState.score}/{activeDivision.quiz.length} in {activeDivision.name}</p>
                    </div>
                    <button 
                       onClick={resetQuiz}
                       className="px-10 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-sm font-bold transition-all flex items-center gap-2"
                    >
                       <RotateCcw size={18} /> Retake Test
                    </button>
                 </div>
               )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

