                    <CheckCircle2 size={16} className="text-blue-500" /> Link physical evidence to the primary suspect.
                  </li>
                </ul>
              </div>
              <button onClick={() => setStep('investigation')} className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-bold transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center gap-2">
                Enter Crime Scene <ArrowRight size={18} />
              </button>
            </div>
            <div className="relative group rounded-3xl overflow-hidden border border-slate-800">
              <img src="https://images.unsplash.com/photo-1558494949-ef010958b92d?q=80&w=2000&auto=format&fit=crop" alt="Server Room" className="w-full h-full object-cover opacity-60 group-hover:scale-105 transition-transform duration-700" />
              <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent" />
              <div className="absolute bottom-6 left-6 right-6">
                <div className="bg-black/40 backdrop-blur-md p-4 rounded-xl border border-white/10">
                   <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest mb-1">Visual Log</p>
                   <p className="text-xs text-white">Rack #7 shows physical tampering. Cooling fans at maximum capacity.</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 'investigation' && (
          <div className="space-y-6">
             <div className="bg-amber-500/10 border border-amber-500/20 p-4 rounded-2xl flex items-center gap-3">
                <AlertCircle className="text-amber-500" />
                <p className="text-xs text-amber-200 font-medium">Use the <b>Evidence Simulator</b> module to pick tools. Click items below to collect them once identified.</p>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {currentCase.clues.map(clue => (
                  <div key={clue.id} className={`p-6 rounded-3xl border transition-all flex flex-col justify-between ${foundClues.includes(clue.id) ? 'bg-blue-600/10 border-blue-500/50 shadow-xl' : 'bg-slate-900 border-slate-800 opacity-60'}`}>
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                         <div className={`p-3 rounded-xl ${foundClues.includes(clue.id) ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                            {clue.name.includes('Blood') ? <Activity size={20} /> : clue.name.includes('Syringe') ? <ShieldAlert size={20} /> : clue.name.includes('Print') ? <Fingerprint size={20} /> : <Camera size={20} />}
                         </div>
                         {foundClues.includes(clue.id) && <CheckCircle2 size={16} className="text-blue-500" />}
                      </div>
                      <h4 className="font-bold text-white">{clue.name}</h4>
                      <p className="text-xs text-slate-500 italic">{clue.description}</p>
                    </div>

                    <div className="mt-6 pt-4 border-t border-slate-800/50">
                       <p className="text-[9px] font-bold text-slate-600 uppercase mb-2">Required Action</p>
                       <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest bg-blue-400/5 px-2 py-1 rounded w-fit">{clue.requiredTool}</p>
                       <button onClick={() => toggleClue(clue.id)} className={`w-full mt-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${foundClues.includes(clue.id) ? 'bg-slate-800 text-slate-400' : 'bg-blue-600 text-white'}`}>
                          {foundClues.includes(clue.id) ? 'Collected' : 'Tag Evidence'}
                       </button>
                    </div>
                  </div>
                ))}
             </div>

             <div className="bg-slate-900 border border-slate-800 p-8 rounded-3xl flex items-center justify-between">
                <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-blue-600/10 rounded-2xl flex items-center justify-center text-blue-500 border border-blue-500/20 shadow-inner">
                    <FileText size={32} />
                  </div>
                  <div>
                    <h3 className="text-xl font-bold">Investigation Dashboard</h3>
                    <p className="text-sm text-slate-400">Total Progress: {Math.round((foundClues.length / currentCase.clues.length) * 100)}%</p>
                  </div>
                </div>
                {foundClues.length === currentCase.clues.length && (
                  <button onClick={() => setStep('lab')} className="px-8 py-4 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-bold shadow-lg shadow-emerald-500/20 transition-all flex items-center gap-2">
                    Submit to Lab <Search size={18} />
                  </button>
                )}
             </div>
          </div>
        )}

        {step === 'lab' && (
          <div className="space-y-8">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {currentCase.clues.map(clue => (
                  <div key={clue.id} className={`bg-slate-900 border border-slate-800 p-8 rounded-3xl transition-all ${!foundClues.includes(clue.id) ? 'opacity-30' : ''}`}>
                    <div className="flex items-start justify-between mb-6">
                       <div className="flex items-center gap-4">
                          <div className="p-4 bg-indigo-600/10 rounded-2xl text-indigo-400 border border-indigo-500/20 shadow-inner">
                             <Microscope size={24} />
                          </div>
                          <div>
                             <h4 className="font-bold text-white uppercase tracking-tight text-lg">{clue.labDivision}</h4>
                             <p className="text-xs text-slate-500">Specimen: {clue.name}</p>
                          </div>
                       </div>
                       {analyzedClues.includes(clue.id) && <span className="bg-emerald-500/10 text-emerald-500 text-[9px] font-bold uppercase tracking-[0.2em] px-2 py-1 rounded">Analysis Complete</span>}
                    </div>

                    <div className="bg-black/30 p-6 rounded-2xl border border-white/5 font-mono text-xs leading-relaxed min-h-[100px] flex items-center justify-center">
                       {analyzedClues.includes(clue.id) ? (
                         <p className="text-blue-300">
                            {clue.id === 'c1' && "DNA MATCH: 99.9% similarity found with VIKTOR KRAZ (Internal ID: 4421-K). Status: ACTIVE."}
                            {clue.id === 'c2' && "TOX REPORT: Midazolam detected. Residue analysis suggests custom pressurized injector delivery."}
                            {clue.id === 'c3' && "RIDGEOLOGY: Loop pattern identified. Matches entry logs for unauthorized server access."}
                            {clue.id === 'c4' && "EXTRACTION: 34 Deleted messages recovered. Communications identified regarding 'The Ghost Operation'."}
                         </p>
                       ) : (
                         <p className="text-slate-600 italic">Waiting for instrument synchronization...</p>
                       )}
                    </div>

                    <button 
                      disabled={!foundClues.includes(clue.id) || analyzedClues.includes(clue.id)}
                      onClick={() => runAnalysis(clue.id)}
                      className="w-full mt-6 py-4 bg-slate-800 hover:bg-slate-700 disabled:opacity-20 rounded-2xl text-xs font-bold uppercase tracking-widest text-white transition-all"
                    >
                      {analyzedClues.includes(clue.id) ? 'Report Generated' : 'Run Instrumentation'}
                    </button>
                  </div>
                ))}
             </div>

             {analyzedClues.length === currentCase.clues.length && (
               <div className="bg-indigo-600 p-8 rounded-3xl shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6 animate-bounce-slow">
                  <div className="text-white">
                    <h3 className="text-2xl font-bold">Scientific Chain Completed</h3>
                    <p className="opacity-90">All evidence points to a specific individual. Proceed to the Grand Jury.</p>
                  </div>
                  <button onClick={() => setStep('verdict')} className="px-10 py-5 bg-white text-indigo-600 rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all active:scale-95">
                    Issue Verdict
                  </button>
               </div>
             )}
          </div>
        )}

        {step === 'verdict' && (
          <div className="space-y-12">
             <div className="text-center space-y-4">
                <h3 className="text-3xl font-bold text-white tracking-tight">Who committed the crime?</h3>
                <p className="text-slate-500 max-w-lg mx-auto">Select the primary suspect based on the scientific evidence gathered. Your choice determines the success of the investigation.</p>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {currentCase.suspects.map(suspect => (
                  <button 
                    key={suspect.id}
                    onClick={() => { setSelectedSuspect(suspect.id); setShowResult(null); }}
                    className={`bg-slate-900 border-2 rounded-3xl p-8 text-left transition-all hover:scale-105 ${selectedSuspect === suspect.id ? 'border-blue-500 shadow-2xl shadow-blue-500/20 bg-blue-500/5' : 'border-slate-800'}`}
                  >
                    <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 ring-4 ring-slate-800/50">
                       <UserPlus size={32} className={selectedSuspect === suspect.id ? 'text-blue-400' : 'text-slate-600'} />
                    </div>
                    <h4 className="text-xl font-bold text-white">{suspect.name}</h4>
                    <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest mb-4">{suspect.role}</p>
                    <div className="space-y-2 pt-4 border-t border-slate-800">
                       <p className="text-[10px] font-bold text-slate-600 uppercase">Suspected Motive</p>
                       <p className="text-xs text-slate-400 italic">"{suspect.motive}"</p>
                    </div>
                  </button>
                ))}
             </div>

             {selectedSuspect && (
               <div className="flex flex-col items-center space-y-6 pt-10">
                  <button onClick={checkVerdict} className="px-12 py-6 bg-rose-600 hover:bg-rose-500 text-white rounded-3xl font-black text-xl uppercase tracking-[0.2em] shadow-2xl shadow-rose-500/30 transition-all flex items-center gap-3 active:scale-95">
                    <Gavel size={28} /> Confirm Arrest
                  </button>

                  {showResult !== null && (
                    <div className={`w-full max-w-2xl p-10 rounded-3xl border-4 animate-in zoom-in duration-500 ${showResult ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-rose-500/10 border-rose-500 text-rose-400'}`}>
                       <div className="flex items-center gap-6">
                          {showResult ? <CheckCircle2 size={64} /> : <AlertCircle size={64} />}
                          <div>
                             <h4 className="text-3xl font-black uppercase tracking-tighter">{showResult ? 'Justice Served' : 'Investigation Failed'}</h4>
                             <p className="text-sm mt-2 opacity-90 leading-relaxed">
                                {currentCase.suspects.find(s => s.id === selectedSuspect)?.evidenceLink}
                             </p>
                          </div>
                       </div>
                       {showResult && (
                         <div className="mt-8 pt-8 border-t border-emerald-500/20 text-center">
                            <p className="text-[10px] font-bold uppercase tracking-widest mb-4 opacity-50">Career Milestones Unlocked</p>
                            <div className="flex justify-center gap-4">
                               <div className="px-4 py-2 bg-emerald-500/20 rounded-lg text-xs font-bold border border-emerald-500/20">DNA Specialist</div>
                               <div className="px-4 py-2 bg-emerald-500/20 rounded-lg text-xs font-bold border border-emerald-500/20">Cyber-Crime Analyst</div>
                            </div>
                         </div>
                       )}
                    </div>
                  )}
               </div>
             )}
          </div>
        )}
      </div>

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-slow {
          animation: bounce-slow 4s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

