      <div className="flex gap-2 p-1.5 bg-slate-900 rounded-2xl border border-slate-800 w-fit">
        <button onClick={() => setStep('briefing')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${step === 'briefing' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>Briefing</button>
        <button onClick={() => setStep('investigation')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${step === 'investigation' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>Scene Scan</button>
        <button onClick={() => setStep('lab')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${step === 'lab' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>Lab Results</button>
        <button onClick={() => setStep('verdict')} className={`px-6 py-2.5 rounded-xl text-xs font-bold transition-all ${step === 'verdict' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>Verdict</button>
      </div>

      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        {step === 'briefing' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-slate-900 border border-slate-800 p-8 rounded-3xl space-y-6 shadow-xl">
              <h3 className="text-xl font-bold flex items-center gap-2 text-white">
                <Clipboard className="text-blue-500" /> Professional Briefing
              </h3>
              <p className="text-slate-300 leading-relaxed text-lg font-serif italic border-l-4 border-blue-600/30 pl-6 py-2">
                "{selectedCase.briefing}"
              </p>
              <div className="pt-6 border-t border-slate-800 space-y-4">
                <h4 className="text-xs font-bold uppercase text-slate-500 tracking-widest">Procedural Benchmarks</h4>
                <ul className="space-y-3">
                  <li className="flex items-center gap-3 text-sm text-slate-300">
                    <CheckCircle2 size={16} className="text-blue-500" /> Locate and tag all primary evidentiary items.
                  </li>
                  <li className="flex items-center gap-3 text-sm text-slate-300">
                    <CheckCircle2 size={16} className="text-blue-500" /> Maintain chain of custody with appropriate tools.
                  </li>
                  <li className="flex items-center gap-3 text-sm text-slate-300">
                    <CheckCircle2 size={16} className="text-blue-500" /> Correlate lab findings with suspect narratives.
                  </li>
                </ul>
              </div>
              <button onClick={() => setStep('investigation')} className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-bold transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center gap-2 active:scale-95">
                Proceed to Incident Scene <ArrowRight size={18} />
              </button>
            </div>
            <div className="relative group rounded-3xl overflow-hidden border border-slate-800 shadow-2xl">
              <img 
                src={selectedCase.id === 'sim-1' ? "https://images.unsplash.com/photo-1558494949-ef010958b92d?q=80&w=2000" : "https://images.unsplash.com/photo-1554224155-8d04cb21cd6c?q=80&w=2000"} 
                alt="Crime Scene" 
                className="w-full h-full object-cover opacity-60 group-hover:scale-110 transition-transform duration-[2000ms]" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-slate-950 via-transparent to-transparent" />
              <div className="absolute bottom-6 left-6 right-6">
                <div className="bg-black/60 backdrop-blur-md p-5 rounded-2xl border border-white/10">
                   <p className="text-[10px] font-black text-blue-400 uppercase tracking-[0.2em] mb-1">Visual Log Entry</p>
                   <p className="text-xs text-white leading-relaxed font-medium">Preliminary sweep indicates high-value evidence clusters near the central workspace.</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {step === 'investigation' && (
          <div className="space-y-6">
             <div className="bg-amber-500/10 border border-amber-500/20 p-5 rounded-2xl flex items-center gap-4">
                <AlertCircle className="text-amber-500 shrink-0" size={24} />
                <p className="text-xs text-amber-200 font-medium leading-relaxed">System Note: Ensure you have read the <b>Evidence Simulator</b> module. Improper tool selection may lead to cross-contamination alerts in the final report.</p>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {selectedCase.clues.map(clue => (
                  <div key={clue.id} className={`p-6 rounded-[2rem] border transition-all flex flex-col justify-between group ${foundClues.includes(clue.id) ? 'bg-blue-600/10 border-blue-500/50 shadow-2xl scale-105 z-10' : 'bg-slate-900 border-slate-800 opacity-60 hover:opacity-100'}`}>
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                         <div className={`p-3.5 rounded-2xl transition-colors ${foundClues.includes(clue.id) ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500 group-hover:bg-slate-700'}`}>
                            {clue.name.includes('Blood') || clue.name.includes('Ledger') ? <Dna size={22} /> : clue.name.includes('Shell') || clue.name.includes('Casing') ? <Search size={22} /> : clue.name.includes('Print') ? <Fingerprint size={22} /> : <Camera size={22} />}
                         </div>
                         {foundClues.includes(clue.id) && <CheckCircle2 size={18} className="text-blue-500" />}
                      </div>
                      <h4 className="font-bold text-white text-lg tracking-tight leading-tight">{clue.name}</h4>
                      <p className="text-[11px] text-slate-500 italic leading-relaxed">{clue.description}</p>
