                    <Gavel size={32} /> Confirm Verdict
                  </button>

                  {showResult !== null && (
                    <div className={`w-full max-w-3xl p-12 rounded-[3rem] border-4 animate-in zoom-in duration-500 ${showResult ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-rose-500/10 border-rose-500 text-rose-400'}`}>
                       <div className="flex flex-col md:flex-row items-center gap-10">
                          <div className={`w-24 h-24 rounded-full flex items-center justify-center border-4 ${showResult ? 'border-emerald-500 bg-emerald-500/20' : 'border-rose-500 bg-rose-500/20'}`}>
                             {showResult ? <CheckCircle2 size={56} /> : <AlertCircle size={56} />}
                          </div>
                          <div className="flex-1 text-center md:text-left space-y-2">
                             <h4 className="text-4xl font-black uppercase tracking-tighter">{showResult ? 'Justice Prevails' : 'Case Dismissed'}</h4>
                             <p className="text-sm font-bold opacity-80 leading-relaxed uppercase tracking-wider">
                                {selectedCase.suspects.find(s => s.id === selectedSuspect)?.evidenceLink}
                             </p>
                          </div>
                       </div>

                       {showResult && (
                         <div className="mt-10 pt-10 border-t border-emerald-500/20">
                            <div className="flex flex-wrap justify-center gap-4">
                               <div className="px-6 py-3 bg-emerald-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-emerald-500/20">Modality Master</div>
                               <div className="px-6 py-3 bg-emerald-500/20 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-emerald-500/20">Analytical Accuracy 100%</div>
                               <button onClick={resetInvestigation} className="px-6 py-3 bg-white text-emerald-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-50">Next Assignment</button>
                            </div>
                         </div>
                       )}
                    </div>
                  )}
               </div>
             )}
          </div>
        )}
      </div>

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-slow {
          animation: bounce-slow 4s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

