import React, { useState, useEffect } from 'react';
import { 
  Home, 
  FlaskConical, 
  PenTool, 
  MessageSquare, 
  ShieldCheck, 
  Moon, 
  Sun, 
  GraduationCap,
  LogOut,
  Library as LibraryIcon,
  User,
  Briefcase
} from 'lucide-react';
import { UserSession, TabType } from './types';
import Login from './components/Login';
import WelcomeAnimation from './components/WelcomeAnimation';
import Dashboard from './modules/Dashboard';
import EvidenceSimulator from './modules/EvidenceSimulator';
import LabInfo from './modules/LabInfo';
import SketchTool from './modules/SketchTool';
import ExamSection from './modules/ExamSection';
import Profile from './modules/Profile';
import ExpertChat from './modules/ExpertChat';
import Library from './modules/Library';
import CasePractice from './modules/CasePractice';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [isDarkMode, setIsDarkMode] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('forenova_session');
    if (savedSession) {
      setSession(JSON.parse(savedSession));
    }
    const savedTheme = localStorage.getItem('forenova_theme');
    if (savedTheme === 'light') setIsDarkMode(false);
  }, []);

  const handleLogin = (username: string) => {
    const newSession: UserSession = {
      username,
      isLoggedIn: true,
      progress: 25,
      quizScores: [],
      joinedAt: new Date().toISOString()
    };
    localStorage.setItem('forenova_session', JSON.stringify(newSession));
    setSession(newSession);
    setShowWelcome(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('forenova_session');
    setSession(null);
    setActiveTab('home');
  };

  const toggleTheme = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    localStorage.setItem('forenova_theme', newMode ? 'dark' : 'light');
  };

  if (!session) {
    return <Login onLogin={handleLogin} darkMode={isDarkMode} />;
  }

  if (showWelcome) {
    return <WelcomeAnimation username={session.username} onComplete={() => setShowWelcome(false)} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard session={session} setActiveTab={setActiveTab} />;
      case 'evidence': return <EvidenceSimulator />;
      case 'lab': return <LabInfo />;
      case 'sketch': return <SketchTool />;
      case 'library': return <Library />;
      case 'exams': return <ExamSection session={session} setSession={setSession} />;
      case 'profile': return <Profile session={session} onLogout={handleLogout} toggleTheme={toggleTheme} isDarkMode={isDarkMode} />;
      case 'expert': return <ExpertChat />;
      case 'cases': return <CasePractice />;
      default: return <Dashboard session={session} setActiveTab={setActiveTab} />;
    }
  };

  const NavItem = ({ icon: Icon, label, tab }: { icon: any, label: string, tab: TabType }) => (
    <button
      onClick={() => setActiveTab(tab)}
      className={`flex items-center gap-4 w-full px-4 py-3 rounded-lg transition-all ${
        activeTab === tab 
          ? 'bg-blue-600/10 text-blue-500 border-r-4 border-blue-500 rounded-r-none' 
          : isDarkMode ? 'text-gray-400 hover:text-white hover:bg-white/5' : 'text-gray-500 hover:text-gray-800 hover:bg-black/5'
      }`}
    >
      <Icon size={20} />
      <span className="text-sm font-medium">{label}</span>
    </button>
  );

  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-[#0a0e17] text-white' : 'bg-slate-50 text-slate-900'}`}>

      {/* Professional Sidebar Navigation */}
      <aside className={`w-64 flex flex-col fixed inset-y-0 z-50 border-r ${isDarkMode ? 'bg-[#0d121f] border-slate-800' : 'bg-white border-slate-200'}`}>
        <div className="p-6">
          <h1 className="text-2xl font-bold tracking-tight text-blue-500">FORENOVA</h1>
        </div>

        <nav className="flex-1 px-2 space-y-1">
          <NavItem icon={Home} label="Home" tab="home" />
          <NavItem icon={Briefcase} label="Cases" tab="cases" />
          <NavItem icon={ShieldCheck} label="Evidence" tab="evidence" />
          <NavItem icon={PenTool} label="Sketch" tab="sketch" />
          <NavItem icon={FlaskConical} label="Lab" tab="lab" />
          <NavItem icon={LibraryIcon} label="Library" tab="library" />
          <NavItem icon={GraduationCap} label="Exams" tab="exams" />
        </nav>

        <div className={`mt-auto p-4 border-t ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}>
          <div className="flex items-center gap-3 mb-6 px-2">
            <div className="w-10 h-10 rounded-full bg-blue-600/20 flex items-center justify-center text-blue-500">
              <User size={20} />
            </div>
            <div>
              <p className="text-sm font-bold truncate max-w-[120px]">{session.username}</p>
              <p className="text-[10px] text-slate-500 uppercase">Forensic Trainee</p>
            </div>
          </div>
          <button 
            onClick={handleLogout}
            className="flex items-center gap-2 text-rose-500 hover:text-rose-400 text-sm font-medium px-2 py-2 w-full rounded-lg hover:bg-rose-500/5 transition-all"
          >
            <LogOut size={16} />
            Sign Out
          </button>
        </div>
      </aside>

      <div className="flex-1 ml-64 min-h-screen">
        <header className={`px-8 py-4 flex justify-end items-center border-b ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}>
          <button onClick={toggleTheme} className={`p-2 rounded-lg ${isDarkMode ? 'hover:bg-slate-800 text-yellow-400' : 'hover:bg-slate-100 text-slate-600'}`}>
            {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
          </button>
        </header>

        <main className="p-8 animate-in fade-in duration-500">
          {renderContent()}
        </main>
      </div>

      <button 
        onClick={() => setActiveTab('expert')}
        className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 text-white rounded-full flex items-center justify-center shadow-lg shadow-blue-500/30 hover:scale-110 transition-transform z-[100]"
      >
        <MessageSquare size={24} />
      </button>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Undo2, 
  Redo2, 
  Save, 
  MousePointer2, 
  Activity,
  Square,
  Minus,
  Download,
  Sparkles,
  ArrowRight,
  Maximize2,
  Box,
  Hash,
  Move,
  RotateCcw,
  Type as TypeIcon,
  Layout,
  Layers,
  Info,
  ChevronRight
} from 'lucide-react';
import { SceneObject, RoomDimensions, PathPoint } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

const ASSETS = {
  structural: [
    { subType: 'Wall', icon: <Minus size={18} />, label: 'Wall Segment', w: 4, d: 0.2, color: '#1e293b' },
    { subType: 'Door', icon: <div className="w-4 h-4 border-l-2 border-b-2 border-slate-400 rounded-bl-full" />, label: 'Entrance', w: 1, d: 1, color: '#64748b' },
    { subType: 'Window', icon: <div className="w-4 h-1 bg-blue-100 border border-blue-300" />, label: 'Window', w: 1.5, d: 0.2, color: '#94a3b8' },
  ],
  investigation: [
    { subType: 'Body', icon: '👤', label: 'Victim/Subject', w: 1.8, d: 0.6, color: '#ef4444', isMarker: true },
    { subType: 'Firearm', icon: '🔫', label: 'Weapon', w: 0.3, d: 0.2, color: '#334155', isMarker: true },
    { subType: 'Blood', icon: '🩸', label: 'Stain/Spatter', w: 0.5, d: 0.5, color: '#b91c1c', isMarker: true },
    { subType: 'Footprints', icon: '👣', label: 'Impression', w: 0.3, d: 0.15, color: '#475569', isMarker: true },
    { subType: 'Marker', icon: <Hash size={18} />, label: 'Evidence Tag', w: 0.2, d: 0.2, color: '#f59e0b', isMarker: true },
  ],
  furniture: [
    { subType: 'Table', icon: <Square size={18} />, label: 'Work Table', w: 2, d: 1, color: '#94a3b8' },
    { subType: 'Bed', icon: <Layout size={18} />, label: 'Bed/Couch', w: 2, d: 1.5, color: '#94a3b8' },
    { subType: 'Chair', icon: <Box size={18} />, label: 'Seating', w: 0.6, d: 0.6, color: '#94a3b8' },
  ]
};

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 12, length: 10 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [caseInfo, setCaseInfo] = useState({
    caseNo: 'FN-' + Math.floor(1000 + Math.random() * 9000),
    investigator: 'Trainee ID-' + Math.floor(100 + Math.random() * 900),
    date: new Date().toLocaleDateString()
  });

  const pixelsPerMeter = 50;
  const padding = 100;

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_v3');
    if (saved) {
      const data = JSON.parse(saved);
      setObjects(data.objects);
      setRoom(data.room);
    } else {
      addObject('Body', 'Marker');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('forenova_sketch_v3', JSON.stringify({ objects, room }));
    draw();
  }, [room, objects, selectedId]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2.5;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;
    const floorW = room.width * pixelsPerMeter;
    const floorH = room.length * pixelsPerMeter;

    // 1. Blueprint Background
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 2. Technical Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    for (let x = 0; x <= room.width; x++) {
      ctx.beginPath();
      ctx.moveTo(startX + x * pixelsPerMeter, startY);
      ctx.lineTo(startX + x * pixelsPerMeter, startY + floorH);
      ctx.stroke();
      if (x % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${x}m`, startX + x * pixelsPerMeter, startY - 10);
      }
    }
    for (let y = 0; y <= room.length; y++) {
      ctx.beginPath();
      ctx.moveTo(startX, startY + y * pixelsPerMeter);
      ctx.lineTo(startX + floorW, startY + y * pixelsPerMeter);
      ctx.stroke();
      if (y % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${y}m`, startX - 25, startY + y * pixelsPerMeter + 4);
      }
    }

    // 3. Room Boundaries
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 3;
    ctx.strokeRect(startX, startY, floorW, floorH);

    // 4. Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Selection Highlight
      if (selectedId === obj.id) {
        ctx.shadowBlur = 15;
        ctx.shadowColor = 'rgba(59, 130, 246, 0.4)';
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        ctx.strokeRect(-drawW/2 - 4, -drawD/2 - 4, drawW + 8, drawD + 8);
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = obj.color + '20';
      ctx.strokeStyle = obj.color;
      ctx.lineWidth = 2;

      // Render based on subType
      if (obj.subType === 'Body') {
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW/2, drawD/2, 0, 0, Math.PI * 2);
        ctx.stroke(); ctx.fill();
        // Head circle
        ctx.beginPath(); ctx.arc(0, -drawD/3, drawW/4, 0, Math.PI * 2); ctx.stroke();
      } else if (obj.subType === 'Wall') {
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(-drawW/2, -drawD/2, drawW, drawD);
      } else if (obj.subType === 'Blood') {
        ctx.fillStyle = '#b91c1c80';
        ctx.beginPath();
        for(let i=0; i<8; i++) {
          const angle = (i/8) * Math.PI * 2;
          const r = (drawW/2) * (0.6 + Math.random() * 0.4);
          ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.closePath(); ctx.fill();
      } else {
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
        ctx.fill();
      }

      // Evidence ID Callout
      if (obj.evidenceId) {
        ctx.restore();
        ctx.save();
        ctx.translate(drawX, drawY);
        ctx.beginPath();
        ctx.arc(drawW/2 + 10, -drawD/2 - 10, 10, 0, Math.PI * 2);
        ctx.fillStyle = '#f59e0b'; ctx.fill();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 10px Inter'; ctx.textAlign = 'center';
        ctx.fillText(obj.evidenceId, drawW/2 + 10, -drawD/2 - 7);
      }

      ctx.restore();
    });

    // 5. Technical Legend (Report Style)
    const legendY = startY + floorH + 40;
    ctx.fillStyle = '#0f172a';
    ctx.font = 'bold 12px Inter';
    ctx.fillText('FORENSIC LEGEND', startX, legendY);

    let legendIdx = 0;
    objects.filter(o => o.evidenceId).forEach((obj, idx) => {
      const lx = startX + (idx % 3) * 200;
      const ly = legendY + 25 + Math.floor(idx / 3) * 20;
      ctx.fillStyle = '#475569';
      ctx.font = '10px JetBrains Mono';
      ctx.fillText(`${obj.evidenceId}: ${obj.subType.toUpperCase()} (at x:${obj.x}m, y:${obj.y}m)`, lx, ly);
    });

    // 6. Signature Block
    const sigY = canvas.height - 40;
    ctx.strokeStyle = '#cbd5e1';
    ctx.beginPath(); ctx.moveTo(startX, sigY); ctx.lineTo(startX + 300, sigY); ctx.stroke();
    ctx.fillStyle = '#94a3b8'; ctx.font = 'italic 10px Inter';
    ctx.fillText('Digital Signature: ' + caseInfo.investigator, startX, sigY + 15);
    ctx.textAlign = 'right';
    ctx.fillText('Case: ' + caseInfo.caseNo + ' | ' + caseInfo.date, startX + floorW, sigY + 15);
  };

  const addObject = (subType: string, type: 'Marker' | 'Furniture' | 'Structural' = 'Marker') => {
    const asset = [...ASSETS.structural, ...ASSETS.investigation, ...ASSETS.furniture].find(a => a.subType === subType);
    const newObj: SceneObject = {
      id: Date.now().toString(),
      type: type,
      subType: subType,
      label: subType,
      x: room.width / 2,
      y: room.length / 2,
      width: asset?.w || 1,
      depth: asset?.d || 1,
      rotation: 0,
      color: asset?.color || '#000',
      evidenceId: asset?.isMarker ? `E${objects.filter(o => o.evidenceId).length + 1}` : undefined
    };
    setObjects(prev => [...prev, newObj]);
    setSelectedId(newObj.id);
  };

  const deleteSelected = () => {
    if (selectedId) {
      setObjects(prev => prev.filter(o => o.id !== selectedId));
      setSelectedId(null);
    }
  };

  const updateObject = (id: string, updates: Partial<SceneObject>) => {
    setObjects(prev => prev.map(o => o.id === id ? { ...o, ...updates } : o));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    // Snap to grid (0.1m increments)
    const snappedX = Math.round((mouseX - dragOffset.x) * 10) / 10;
    const snappedY = Math.round((mouseY - dragOffset.y) * 10) / 10;

    updateObject(selectedId, { x: snappedX, y: snappedY });
  };

  const generateAI = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a forensic sketch JSON for: "${prompt}".
        Output JSON: { room: {width, length}, objects: [{subType, x, y, width, depth, rotation, evidenceId}] }.
        subTypes: Body, Firearm, Blood, Footprints, Wall, Table, Bed, Chair, Door, Window.
        x and y are meters from top-left.`,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              room: {
                type: Type.OBJECT,
                properties: { width: {type: Type.NUMBER}, length: {type: Type.NUMBER} },
                required: ['width', 'length']
              },
              objects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    subType: {type: Type.STRING},
                    x: {type: Type.NUMBER},
                    y: {type: Type.NUMBER},
                    width: {type: Type.NUMBER},
                    depth: {type: Type.NUMBER},
                    rotation: {type: Type.NUMBER},
                    evidenceId: {type: Type.STRING}
                  }
                }
              }
            }
          }
        }
      });
      const data = JSON.parse(response.text);
      setRoom(data.room);
      setObjects(data.objects.map((o:any, i:number) => ({ ...o, id: 'ai-'+i, type: 'Marker' })));
    } catch (e) { console.error(e); }
    finally { setIsGenerating(false); }
  };

  const selectedObj = objects.find(o => o.id === selectedId);

  return (
    <div className="flex flex-col gap-6 h-full max-w-[1600px] mx-auto pb-10">
      {/* Top AI Bar */}
      <div className="bg-slate-900 border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
        <div className="relative z-10 flex items-center gap-6">
          <div className="p-4 bg-blue-600/10 rounded-2xl border border-blue-500/20 text-blue-500">
             <Sparkles size={28} className={isGenerating ? 'animate-spin' : ''} />
          </div>
          <div className="flex-1">
             <h2 className="text-white font-bold text-lg mb-2">ForeNova Scene Intelligence</h2>
             <div className="relative">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="E.g., 'A 5x5 room with a body near the south wall and a handgun on the floor...'"
                  className="w-full bg-black/40 border border-white/10 rounded-2xl py-4 pl-6 pr-36 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all placeholder:text-slate-600"
                />
                <button 
                  onClick={generateAI}
                  disabled={isGenerating || !prompt.trim()}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white px-6 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 transition-all shadow-lg"
                >
                  Draft Scene <ArrowRight size={14} />
                </button>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-[700px]">
        {/* Left: Asset Toolbox */}
        <div className="lg:col-span-2 flex flex-col gap-4 overflow-y-auto max-h-[800px] custom-scrollbar">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl space-y-6">
              <div>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Layers size={14} /> Structural
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.structural.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Structural')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-blue-600/20 hover:border-blue-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Activity size={14} /> Investigation
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.investigation.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Marker')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-rose-600/20 hover:border-rose-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center text-lg group-hover:scale-125 transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Box size={14} /> Furniture
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.furniture.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Furniture')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-emerald-600/20 hover:border-emerald-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>
           </div>
        </div>

        {/* Center: Drawing Area */}
        <div className="lg:col-span-7 bg-slate-950 border border-slate-800 rounded-[3rem] overflow-auto shadow-2xl flex flex-col relative group">
           <div className="absolute top-8 left-8 z-10 flex gap-2">
              <div className="bg-blue-600/20 text-blue-400 px-4 py-2 rounded-xl border border-blue-500/20 text-[10px] font-black uppercase tracking-widest">Blueprint Mode</div>
              <div className="bg-slate-900/80 text-slate-500 px-4 py-2 rounded-xl border border-white/5 text-[10px] font-bold uppercase tracking-widest">Grid: 0.5m</div>
           </div>

           <div className="flex-1 flex items-center justify-center p-12">
              <canvas
                ref={canvasRef}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={() => setIsDragging(false)}
                className="shadow-[0_0_100px_rgba(0,0,0,0.5)] cursor-crosshair transition-transform duration-500"
              />
           </div>

           <div className="p-6 bg-slate-900/50 border-t border-white/5 flex justify-between items-center backdrop-blur-md">
              <div className="flex items-center gap-6">
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, width: Math.max(5, r.width-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">W: {room.width}m</span>
                    <button onClick={() => setRoom(r => ({...r, width: r.width+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, length: Math.max(5, r.length-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">L: {room.length}m</span>
                    <button onClick={() => setRoom(r => ({...r, length: r.length+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
              </div>
              <button 
                onClick={() => {
                  const canvas = canvasRef.current;
                  if (!canvas) return;
                  const link = document.createElement('a');
                  link.download = `Forensic_Sketch_${caseInfo.caseNo}.png`;
                  link.href = canvas.toDataURL();
                  link.click();
                }}
                className="flex items-center gap-2 px-6 py-3 bg-white text-slate-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-50 transition-all shadow-xl"
              >
                <Download size={16} /> Export Blueprint
              </button>
           </div>
        </div>

        {/* Right: Properties Panel */}
        <div className="lg:col-span-3 space-y-4">
           {selectedObj ? (
             <div className="bg-slate-900 border-2 border-blue-500/30 p-8 rounded-[2.5rem] shadow-2xl space-y-8 animate-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                         <Settings size={20} />
                      </div>
                      <h3 className="font-bold text-white text-lg uppercase tracking-tight">Properties</h3>
                   </div>
                   <button onClick={deleteSelected} className="p-3 bg-rose-600/10 text-rose-500 hover:bg-rose-600 hover:text-white rounded-xl transition-all">
                      <Trash2 size={18} />
                   </button>
                </div>

                <div className="space-y-6">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Identification</label>
                      <div className="flex gap-2">
                         <div className="flex-1 bg-black/40 p-4 rounded-xl border border-white/5">
                            <p className="text-[8px] text-slate-600 uppercase mb-1">Type</p>
                            <p className="text-xs font-bold text-white">{selectedObj.subType}</p>
                         </div>
                         <div className="flex-1 bg-black/40 p-4 rounded-xl border border-white/5">
                            <p className="text-[8px] text-slate-600 uppercase mb-1">Evidence ID</p>
                            <input 
                              type="text" 
                              value={selectedObj.evidenceId || ''} 
                              onChange={(e) => updateObject(selectedObj.id, { evidenceId: e.target.value })}
                              className="bg-transparent text-xs font-bold text-blue-400 outline-none w-full"
                            />
                         </div>
                      </div>
                   </div>

                   <div className="space-y-4">
                      <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Transform</label>
                      <div className="space-y-6">
                        <div className="space-y-3">
                           <div className="flex justify-between text-[10px] text-slate-400">
                              <span>Rotation</span>
                              <span className="font-mono text-blue-400">{selectedObj.rotation}°</span>
                           </div>
                           <input 
                             type="range" min="0" max="360" 
                             value={selectedObj.rotation} 
                             onChange={(e) => updateObject(selectedObj.id, { rotation: parseInt(e.target.value) })}
                             className="w-full accent-blue-600 h-1 bg-slate-800 rounded-full"
                           />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                           <div className="space-y-2">
                              <span className="text-[9px] text-slate-500 uppercase">Width (m)</span>
                              <input 
                                type="number" step="0.1"
                                value={selectedObj.width}
                                onChange={(e) => updateObject(selectedObj.id, { width: parseFloat(e.target.value) })}
                                className="w-full bg-black/40 p-3 rounded-lg border border-white/5 text-xs text-white"
                              />
                           </div>
                           <div className="space-y-2">
                              <span className="text-[9px] text-slate-500 uppercase">Depth (m)</span>
                              <input 
                                type="number" step="0.1"
                                value={selectedObj.depth}
                                onChange={(e) => updateObject(selectedObj.id, { depth: parseFloat(e.target.value) })}
                                className="w-full bg-black/40 p-3 rounded-lg border border-white/5 text-xs text-white"
                              />
                           </div>
                        </div>
                      </div>
                   </div>

                   <div className="bg-blue-600/5 p-6 rounded-2xl border border-blue-500/10 space-y-3">
                      <h4 className="text-[9px] font-black text-blue-500 uppercase tracking-widest flex items-center gap-2">
                         <Info size={12} /> Forensic Tip
                      </h4>
                      <p className="text-[10px] text-slate-400 leading-relaxed italic">
                         Markers for biological evidence ({selectedObj.subType}) should be cross-referenced with photography logs before final report submission.
                      </p>
                   </div>
                </div>
             </div>
           ) : (
             <div className="bg-slate-900 border border-slate-800 p-10 rounded-[2.5rem] h-full flex flex-col items-center justify-center text-center space-y-6 opacity-50 grayscale">
                <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center text-slate-600">
                   <MousePointer2 size={32} />
                </div>
                <div>
                   <h3 className="font-bold text-white uppercase tracking-tight">Interactive Board</h3>
                   <p className="text-[10px] text-slate-500 max-w-[150px] mx-auto mt-2 leading-relaxed">Select an item on the blueprint to calibrate its forensic properties.</p>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default SketchTool;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Undo2, 
  Redo2, 
  Save, 
  MousePointer2, 
  Activity,
  Square,
  Minus,
  Download,
  Sparkles,
  ArrowRight,
  Maximize2,
  Box,
  Hash,
  Move,
  RotateCcw,
  Type as TypeIcon,
  Layout,
  Layers,
  Info,
  ChevronRight,
  // Fix: Import missing Settings icon from lucide-react
  Settings
} from 'lucide-react';
import { SceneObject, RoomDimensions, PathPoint } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

const ASSETS = {
  structural: [
    // Fix: Add isMarker: false to structural assets to satisfy type checking in addObject
    { subType: 'Wall', icon: <Minus size={18} />, label: 'Wall Segment', w: 4, d: 0.2, color: '#1e293b', isMarker: false },
    { subType: 'Door', icon: <div className="w-4 h-4 border-l-2 border-b-2 border-slate-400 rounded-bl-full" />, label: 'Entrance', w: 1, d: 1, color: '#64748b', isMarker: false },
    { subType: 'Window', icon: <div className="w-4 h-1 bg-blue-100 border border-blue-300" />, label: 'Window', w: 1.5, d: 0.2, color: '#94a3b8', isMarker: false },
  ],
  investigation: [
    { subType: 'Body', icon: '👤', label: 'Victim/Subject', w: 1.8, d: 0.6, color: '#ef4444', isMarker: true },
    { subType: 'Firearm', icon: '🔫', label: 'Weapon', w: 0.3, d: 0.2, color: '#334155', isMarker: true },
    { subType: 'Blood', icon: '🩸', label: 'Stain/Spatter', w: 0.5, d: 0.5, color: '#b91c1c', isMarker: true },
    { subType: 'Footprints', icon: '👣', label: 'Impression', w: 0.3, d: 0.15, color: '#475569', isMarker: true },
    { subType: 'Marker', icon: <Hash size={18} />, label: 'Evidence Tag', w: 0.2, d: 0.2, color: '#f59e0b', isMarker: true },
  ],
  furniture: [
    // Fix: Add isMarker: false to furniture assets to satisfy type checking in addObject
    { subType: 'Table', icon: <Square size={18} />, label: 'Work Table', w: 2, d: 1, color: '#94a3b8', isMarker: false },
    { subType: 'Bed', icon: <Layout size={18} />, label: 'Bed/Couch', w: 2, d: 1.5, color: '#94a3b8', isMarker: false },
    { subType: 'Chair', icon: <Box size={18} />, label: 'Seating', w: 0.6, d: 0.6, color: '#94a3b8', isMarker: false },
  ]
};

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 12, length: 10 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [caseInfo, setCaseInfo] = useState({
    caseNo: 'FN-' + Math.floor(1000 + Math.random() * 9000),
    investigator: 'Trainee ID-' + Math.floor(100 + Math.random() * 900),
    date: new Date().toLocaleDateString()
  });

  const pixelsPerMeter = 50;
  const padding = 100;

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_v3');
    if (saved) {
      const data = JSON.parse(saved);
      setObjects(data.objects);
      setRoom(data.room);
    } else {
      addObject('Body', 'Marker');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('forenova_sketch_v3', JSON.stringify({ objects, room }));
    draw();
  }, [room, objects, selectedId]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2.5;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;
    const floorW = room.width * pixelsPerMeter;
    const floorH = room.length * pixelsPerMeter;

    // 1. Blueprint Background
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 2. Technical Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    for (let x = 0; x <= room.width; x++) {
      ctx.beginPath();
      ctx.moveTo(startX + x * pixelsPerMeter, startY);
      ctx.lineTo(startX + x * pixelsPerMeter, startY + floorH);
      ctx.stroke();
      if (x % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${x}m`, startX + x * pixelsPerMeter, startY - 10);
      }
    }
    for (let y = 0; y <= room.length; y++) {
      ctx.beginPath();
      ctx.moveTo(startX, startY + y * pixelsPerMeter);
      ctx.lineTo(startX + floorW, startY + y * pixelsPerMeter);
      ctx.stroke();
      if (y % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${y}m`, startX - 25, startY + y * pixelsPerMeter + 4);
      }
    }

    // 3. Room Boundaries
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 3;
    ctx.strokeRect(startX, startY, floorW, floorH);

    // 4. Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Selection Highlight
      if (selectedId === obj.id) {
        ctx.shadowBlur = 15;
        ctx.shadowColor = 'rgba(59, 130, 246, 0.4)';
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        ctx.strokeRect(-drawW/2 - 4, -drawD/2 - 4, drawW + 8, drawD + 8);
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = obj.color + '20';
      ctx.strokeStyle = obj.color;
      ctx.lineWidth = 2;

      // Render based on subType
      if (obj.subType === 'Body') {
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW/2, drawD/2, 0, 0, Math.PI * 2);
        ctx.stroke(); ctx.fill();
        // Head circle
        ctx.beginPath(); ctx.arc(0, -drawD/3, drawW/4, 0, Math.PI * 2); ctx.stroke();
      } else if (obj.subType === 'Wall') {
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(-drawW/2, -drawD/2, drawW, drawD);
      } else if (obj.subType === 'Blood') {
        ctx.fillStyle = '#b91c1c80';
        ctx.beginPath();
        for(let i=0; i<8; i++) {
          const angle = (i/8) * Math.PI * 2;
          const r = (drawW/2) * (0.6 + Math.random() * 0.4);
          ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.closePath(); ctx.fill();
      } else {
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
        ctx.fill();
      }

      // Evidence ID Callout
      if (obj.evidenceId) {
        ctx.restore();
        ctx.save();
        ctx.translate(drawX, drawY);
        ctx.beginPath();
        ctx.arc(drawW/2 + 10, -drawD/2 - 10, 10, 0, Math.PI * 2);
        ctx.fillStyle = '#f59e0b'; ctx.fill();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 10px Inter'; ctx.textAlign = 'center';
        ctx.fillText(obj.evidenceId, drawW/2 + 10, -drawD/2 - 7);
      }

      ctx.restore();
    });

    // 5. Technical Legend (Report Style)
    const legendY = startY + floorH + 40;
    ctx.fillStyle = '#0f172a';
    ctx.font = 'bold 12px Inter';
    ctx.fillText('FORENSIC LEGEND', startX, legendY);

    let legendIdx = 0;
    objects.filter(o => o.evidenceId).forEach((obj, idx) => {
      const lx = startX + (idx % 3) * 200;
      const ly = legendY + 25 + Math.floor(idx / 3) * 20;
      ctx.fillStyle = '#475569';
      ctx.font = '10px JetBrains Mono';
      ctx.fillText(`${obj.evidenceId}: ${obj.subType.toUpperCase()} (at x:${obj.x}m, y:${obj.y}m)`, lx, ly);
    });

    // 6. Signature Block
    const sigY = canvas.height - 40;
    ctx.strokeStyle = '#cbd5e1';
    ctx.beginPath(); ctx.moveTo(startX, sigY); ctx.lineTo(startX + 300, sigY); ctx.stroke();
    ctx.fillStyle = '#94a3b8'; ctx.font = 'italic 10px Inter';
    ctx.fillText('Digital Signature: ' + caseInfo.investigator, startX, sigY + 15);
    ctx.textAlign = 'right';
    ctx.fillText('Case: ' + caseInfo.caseNo + ' | ' + caseInfo.date, startX + floorW, sigY + 15);
  };

  // Fix: Changed type parameter to match SceneObject defined types ('Wall' instead of 'Structural')
  const addObject = (subType: string, type: 'Marker' | 'Furniture' | 'Wall' = 'Marker') => {
    const asset = [...ASSETS.structural, ...ASSETS.investigation, ...ASSETS.furniture].find(a => a.subType === subType);
    const newObj: SceneObject = {
      id: Date.now().toString(),
      type: type,
      subType: subType,
      label: subType,
      x: room.width / 2,
      y: room.length / 2,
      width: asset?.w || 1,
      depth: asset?.d || 1,
      rotation: 0,
      color: asset?.color || '#000',
      evidenceId: (asset as any)?.isMarker ? `E${objects.filter(o => o.evidenceId).length + 1}` : undefined
    };
    setObjects(prev => [...prev, newObj]);
    setSelectedId(newObj.id);
  };

  const deleteSelected = () => {
    if (selectedId) {
      setObjects(prev => prev.filter(o => o.id !== selectedId));
      setSelectedId(null);
    }
  };

  const updateObject = (id: string, updates: Partial<SceneObject>) => {
    setObjects(prev => prev.map(o => o.id === id ? { ...o, ...updates } : o));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    // Snap to grid (0.1m increments)
    const snappedX = Math.round((mouseX - dragOffset.x) * 10) / 10;
    const snappedY = Math.round((mouseY - dragOffset.y) * 10) / 10;

    updateObject(selectedId, { x: snappedX, y: snappedY });
  };

  const generateAI = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a forensic sketch JSON for: "${prompt}".
        Output JSON: { room: {width, length}, objects: [{subType, x, y, width, depth, rotation, evidenceId}] }.
        subTypes: Body, Firearm, Blood, Footprints, Wall, Table, Bed, Chair, Door, Window.
        x and y are meters from top-left.`,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              room: {
                type: Type.OBJECT,
                properties: { width: {type: Type.NUMBER}, length: {type: Type.NUMBER} },
                required: ['width', 'length']
              },
              objects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    subType: {type: Type.STRING},
                    x: {type: Type.NUMBER},
                    y: {type: Type.NUMBER},
                    width: {type: Type.NUMBER},
                    depth: {type: Type.NUMBER},
                    rotation: {type: Type.NUMBER},
                    evidenceId: {type: Type.STRING}
                  }
                }
              }
            }
          }
        }
      });
      const data = JSON.parse(response.text);
      setRoom(data.room);
      setObjects(data.objects.map((o:any, i:number) => ({ ...o, id: 'ai-'+i, type: 'Marker' })));
    } catch (e) { console.error(e); }
    finally { setIsGenerating(false); }
  };

  const selectedObj = objects.find(o => o.id === selectedId);

  return (
    <div className="flex flex-col gap-6 h-full max-w-[1600px] mx-auto pb-10">
      {/* Top AI Bar */}
      <div className="bg-slate-900 border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
        <div className="relative z-10 flex items-center gap-6">
          <div className="p-4 bg-blue-600/10 rounded-2xl border border-blue-500/20 text-blue-500">
             <Sparkles size={28} className={isGenerating ? 'animate-spin' : ''} />
          </div>
          <div className="flex-1">
             <h2 className="text-white font-bold text-lg mb-2">ForeNova Scene Intelligence</h2>
             <div className="relative">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="E.g., 'A 5x5 room with a body near the south wall and a handgun on the floor...'"
                  className="w-full bg-black/40 border border-white/10 rounded-2xl py-4 pl-6 pr-36 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all placeholder:text-slate-600"
                />
                <button 
                  onClick={generateAI}
                  disabled={isGenerating || !prompt.trim()}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white px-6 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 transition-all shadow-lg"
                >
                  Draft Scene <ArrowRight size={14} />
                </button>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-[700px]">
        {/* Left: Asset Toolbox */}
        <div className="lg:col-span-2 flex flex-col gap-4 overflow-y-auto max-h-[800px] custom-scrollbar">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl space-y-6">
              <div>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Layers size={14} /> Structural
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.structural.map(a => (
                     // Fix: Pass 'Wall' as the generic structural type for these assets
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Wall')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-blue-600/20 hover:border-blue-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Activity size={14} /> Investigation
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.investigation.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Marker')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-rose-600/20 hover:border-rose-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center text-lg group-hover:scale-125 transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Box size={14} /> Furniture
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.furniture.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Furniture')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-emerald-600/20 hover:border-emerald-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>
           </div>
        </div>

        {/* Center: Drawing Area */}
        <div className="lg:col-span-7 bg-slate-950 border border-slate-800 rounded-[3rem] overflow-auto shadow-2xl flex flex-col relative group">
           <div className="absolute top-8 left-8 z-10 flex gap-2">
              <div className="bg-blue-600/20 text-blue-400 px-4 py-2 rounded-xl border border-blue-500/20 text-[10px] font-black uppercase tracking-widest">Blueprint Mode</div>
              <div className="bg-slate-900/80 text-slate-500 px-4 py-2 rounded-xl border border-white/5 text-[10px] font-bold uppercase tracking-widest">Grid: 0.5m</div>
           </div>

           <div className="flex-1 flex items-center justify-center p-12">
              <canvas
                ref={canvasRef}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={() => setIsDragging(false)}
                className="shadow-[0_0_100px_rgba(0,0,0,0.5)] cursor-crosshair transition-transform duration-500"
              />
           </div>

           <div className="p-6 bg-slate-900/50 border-t border-white/5 flex justify-between items-center backdrop-blur-md">
              <div className="flex items-center gap-6">
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, width: Math.max(5, r.width-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">W: {room.width}m</span>
                    <button onClick={() => setRoom(r => ({...r, width: r.width+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, length: Math.max(5, r.length-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">L: {room.length}m</span>
                    <button onClick={() => setRoom(r => ({...r, length: r.length+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
              </div>
              <button 
                onClick={() => {
                  const canvas = canvasRef.current;
                  if (!canvas) return;
                  const link = document.createElement('a');
                  link.download = `Forensic_Sketch_${caseInfo.caseNo}.png`;
                  link.href = canvas.toDataURL();
                  link.click();
                }}
                className="flex items-center gap-2 px-6 py-3 bg-white text-slate-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-50 transition-all shadow-xl"
              >
                <Download size={16} /> Export Blueprint
              </button>
           </div>
        </div>

        {/* Right: Properties Panel */}
        <div className="lg:col-span-3 space-y-4">
           {selectedObj ? (
             <div className="bg-slate-900 border-2 border-blue-500/30 p-8 rounded-[2.5rem] shadow-2xl space-y-8 animate-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                         <Settings size={20} />
                      </div>
                      <h3 className="font-bold text-white text-lg uppercase tracking-tight">Properties</h3>
                   </div>
                   <button onClick={deleteSelected} className="p-3 bg-rose-600/10 text-rose-500 hover:bg-rose-600 hover:text-white rounded-xl transition-all">
                      <Trash2 size={18} />
                   </button>
                </div>

                <div className="space-y-6">
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Identification</label>
                      <div className="flex gap-2">
                         <div className="flex-1 bg-black/40 p-4 rounded-xl border border-white/5">
                            <p className="text-[8px] text-slate-600 uppercase mb-1">Type</p>
                            <p className="text-xs font-bold text-white">{selectedObj.subType}</p>
                         </div>
                         <div className="flex-1 bg-black/40 p-4 rounded-xl border border-white/5">
                            <p className="text-[8px] text-slate-600 uppercase mb-1">Evidence ID</p>
                            <input 
                              type="text" 
                              value={selectedObj.evidenceId || ''} 
                              onChange={(e) => updateObject(selectedObj.id, { evidenceId: e.target.value })}
                              className="bg-transparent text-xs font-bold text-blue-400 outline-none w-full"
                            />
                         </div>
                      </div>
                   </div>

                   <div className="space-y-4">
                      <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Transform</label>
                      <div className="space-y-6">
                        <div className="space-y-3">
                           <div className="flex justify-between text-[10px] text-slate-400">
                              <span>Rotation</span>
                              <span className="font-mono text-blue-400">{selectedObj.rotation}°</span>
                           </div>
                           <input 
                             type="range" min="0" max="360" 
                             value={selectedObj.rotation} 
                             onChange={(e) => updateObject(selectedObj.id, { rotation: parseInt(e.target.value) })}
                             className="w-full accent-blue-600 h-1 bg-slate-800 rounded-full"
                           />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                           <div className="space-y-2">
                              <span className="text-[9px] text-slate-500 uppercase">Width (m)</span>
                              <input 
                                type="number" step="0.1"
                                value={selectedObj.width}
                                onChange={(e) => updateObject(selectedObj.id, { width: parseFloat(e.target.value) })}
                                className="w-full bg-black/40 p-3 rounded-lg border border-white/5 text-xs text-white"
                              />
                           </div>
                           <div className="space-y-2">
                              <span className="text-[9px] text-slate-500 uppercase">Depth (m)</span>
                              <input 
                                type="number" step="0.1"
                                value={selectedObj.depth}
                                onChange={(e) => updateObject(selectedObj.id, { depth: parseFloat(e.target.value) })}
                                className="w-full bg-black/40 p-3 rounded-lg border border-white/5 text-xs text-white"
                              />
                           </div>
                        </div>
                      </div>
                   </div>

                   <div className="bg-blue-600/5 p-6 rounded-2xl border border-blue-500/10 space-y-3">
                      <h4 className="text-[9px] font-black text-blue-500 uppercase tracking-widest flex items-center gap-2">
                         <Info size={12} /> Forensic Tip
                      </h4>
                      <p className="text-[10px] text-slate-400 leading-relaxed italic">
                         Markers for biological evidence ({selectedObj.subType}) should be cross-referenced with photography logs before final report submission.
                      </p>
                   </div>
                </div>
             </div>
           ) : (
             <div className="bg-slate-900 border border-slate-800 p-10 rounded-[2.5rem] h-full flex flex-col items-center justify-center text-center space-y-6 opacity-50 grayscale">
                <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center text-slate-600">
                   <MousePointer2 size={32} />
                </div>
                <div>
                   <h3 className="font-bold text-white uppercase tracking-tight">Interactive Board</h3>
                   <p className="text-[10px] text-slate-500 max-w-[150px] mx-auto mt-2 leading-relaxed">Select an item on the blueprint to calibrate its forensic properties.</p>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default SketchTool;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Plus, 
  Trash2, 
  Undo2, 
  Redo2, 
  Save, 
  MousePointer2, 
  Activity,
  Square,
  Minus,
  Download,
  Sparkles,
  ArrowRight,
  Maximize2,
  Box,
  Hash,
  Move,
  RotateCcw,
  Type as TypeIcon,
  Layout,
  Layers,
  Info,
  ChevronRight,
  // Fix: Import missing Settings icon from lucide-react
  Settings
} from 'lucide-react';
import { SceneObject, RoomDimensions, PathPoint } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

const ASSETS = {
  structural: [
    // Fix: Add isMarker: false to structural assets to satisfy type checking in addObject
    { subType: 'Wall', icon: <Minus size={18} />, label: 'Wall Segment', w: 4, d: 0.2, color: '#1e293b', isMarker: false },
    { subType: 'Door', icon: <div className="w-4 h-4 border-l-2 border-b-2 border-slate-400 rounded-bl-full" />, label: 'Entrance', w: 1, d: 1, color: '#64748b', isMarker: false },
    { subType: 'Window', icon: <div className="w-4 h-1 bg-blue-100 border border-blue-300" />, label: 'Window', w: 1.5, d: 0.2, color: '#94a3b8', isMarker: false },
  ],
  investigation: [
    { subType: 'Body', icon: '👤', label: 'Victim/Subject', w: 1.8, d: 0.6, color: '#ef4444', isMarker: true },
    { subType: 'Firearm', icon: '🔫', label: 'Weapon', w: 0.3, d: 0.2, color: '#334155', isMarker: true },
    { subType: 'Blood', icon: '🩸', label: 'Stain/Spatter', w: 0.5, d: 0.5, color: '#b91c1c', isMarker: true },
    { subType: 'Footprints', icon: '👣', label: 'Impression', w: 0.3, d: 0.15, color: '#475569', isMarker: true },
    { subType: 'Marker', icon: <Hash size={18} />, label: 'Evidence Tag', w: 0.2, d: 0.2, color: '#f59e0b', isMarker: true },
  ],
  furniture: [
    // Fix: Add isMarker: false to furniture assets to satisfy type checking in addObject
    { subType: 'Table', icon: <Square size={18} />, label: 'Work Table', w: 2, d: 1, color: '#94a3b8', isMarker: false },
    { subType: 'Bed', icon: <Layout size={18} />, label: 'Bed/Couch', w: 2, d: 1.5, color: '#94a3b8', isMarker: false },
    { subType: 'Chair', icon: <Box size={18} />, label: 'Seating', w: 0.6, d: 0.6, color: '#94a3b8', isMarker: false },
  ]
};

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 12, length: 10 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [caseInfo, setCaseInfo] = useState({
    caseNo: 'FN-' + Math.floor(1000 + Math.random() * 9000),
    investigator: 'Trainee ID-' + Math.floor(100 + Math.random() * 900),
    date: new Date().toLocaleDateString()
  });

  const pixelsPerMeter = 50;
  const padding = 100;

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_v3');
    if (saved) {
      const data = JSON.parse(saved);
      setObjects(data.objects);
      setRoom(data.room);
    } else {
      addObject('Body', 'Marker');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('forenova_sketch_v3', JSON.stringify({ objects, room }));
    draw();
  }, [room, objects, selectedId]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2.5;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;
    const floorW = room.width * pixelsPerMeter;
    const floorH = room.length * pixelsPerMeter;

    // 1. Blueprint Background
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 2. Technical Grid
    ctx.strokeStyle = '#e2e8f0';
    ctx.lineWidth = 1;
    for (let x = 0; x <= room.width; x++) {
      ctx.beginPath();
      ctx.moveTo(startX + x * pixelsPerMeter, startY);
      ctx.lineTo(startX + x * pixelsPerMeter, startY + floorH);
      ctx.stroke();
      if (x % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${x}m`, startX + x * pixelsPerMeter, startY - 10);
      }
    }
    for (let y = 0; y <= room.length; y++) {
      ctx.beginPath();
      ctx.moveTo(startX, startY + y * pixelsPerMeter);
      ctx.lineTo(startX + floorW, startY + y * pixelsPerMeter);
      ctx.stroke();
      if (y % 5 === 0) {
        ctx.fillStyle = '#94a3b8';
        ctx.font = '10px JetBrains Mono';
        ctx.fillText(`${y}m`, startX - 25, startY + y * pixelsPerMeter + 4);
      }
    }

    // 3. Room Boundaries
    ctx.strokeStyle = '#334155';
    ctx.lineWidth = 3;
    ctx.strokeRect(startX, startY, floorW, floorH);

    // 4. Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Selection Highlight
      if (selectedId === obj.id) {
        ctx.shadowBlur = 15;
        ctx.shadowColor = 'rgba(59, 130, 246, 0.4)';
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 2;
        ctx.strokeRect(-drawW/2 - 4, -drawD/2 - 4, drawW + 8, drawD + 8);
        ctx.shadowBlur = 0;
      }

      ctx.fillStyle = obj.color + '20';
      ctx.strokeStyle = obj.color;
      ctx.lineWidth = 2;

      // Render based on subType
      if (obj.subType === 'Body') {
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW/2, drawD/2, 0, 0, Math.PI * 2);
        ctx.stroke(); ctx.fill();
        // Head circle
        ctx.beginPath(); ctx.arc(0, -drawD/3, drawW/4, 0, Math.PI * 2); ctx.stroke();
      } else if (obj.subType === 'Wall') {
        ctx.fillStyle = '#1e293b';
        ctx.fillRect(-drawW/2, -drawD/2, drawW, drawD);
      } else if (obj.subType === 'Blood') {
        ctx.fillStyle = '#b91c1c80';
        ctx.beginPath();
        for(let i=0; i<8; i++) {
          const angle = (i/8) * Math.PI * 2;
          const r = (drawW/2) * (0.6 + Math.random() * 0.4);
          ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.closePath(); ctx.fill();
      } else {
        ctx.strokeRect(-drawW/2, -drawD/2, drawW, drawD);
        ctx.fill();
      }

      // Evidence ID Callout
      if (obj.evidenceId) {
        ctx.restore();
        ctx.save();
        ctx.translate(drawX, drawY);
        ctx.beginPath();
        ctx.arc(drawW/2 + 10, -drawD/2 - 10, 10, 0, Math.PI * 2);
        ctx.fillStyle = '#f59e0b'; ctx.fill();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 10px Inter'; ctx.textAlign = 'center';
        ctx.fillText(obj.evidenceId, drawW/2 + 10, -drawD/2 - 7);
      }

      ctx.restore();
    });

    // 5. Technical Legend (Report Style)
    const legendY = startY + floorH + 40;
    ctx.fillStyle = '#0f172a';
    ctx.font = 'bold 12px Inter';
    // Changed "FORENSIC LEGEND" to "FORENSIC EVIDENCE"
    ctx.fillText('FORENSIC EVIDENCE', startX, legendY);

    let legendIdx = 0;
    objects.filter(o => o.evidenceId).forEach((obj, idx) => {
      const lx = startX + (idx % 3) * 200;
      const ly = legendY + 25 + Math.floor(idx / 3) * 20;
      ctx.fillStyle = '#475569';
      ctx.font = '10px JetBrains Mono';
      ctx.fillText(`${obj.evidenceId}: ${obj.subType.toUpperCase()} (at x:${obj.x}m, y:${obj.y}m)`, lx, ly);
    });

    // 6. Signature Block
    const sigY = canvas.height - 40;
    ctx.strokeStyle = '#cbd5e1';
    ctx.beginPath(); ctx.moveTo(startX, sigY); ctx.lineTo(startX + 300, sigY); ctx.stroke();
    ctx.fillStyle = '#94a3b8'; ctx.font = 'italic 10px Inter';
    ctx.fillText('Digital Signature: ' + caseInfo.investigator, startX, sigY + 15);
    ctx.textAlign = 'right';
    ctx.fillText('Case: ' + caseInfo.caseNo + ' | ' + caseInfo.date, startX + floorW, sigY + 15);
  };

  // Fix: Changed type parameter to match SceneObject defined types ('Wall' instead of 'Structural')
  const addObject = (subType: string, type: 'Marker' | 'Furniture' | 'Wall' = 'Marker') => {
    const asset = [...ASSETS.structural, ...ASSETS.investigation, ...ASSETS.furniture].find(a => a.subType === subType);
    const newObj: SceneObject = {
      id: Date.now().toString(),
      type: type,
      subType: subType,
      label: subType,
      x: room.width / 2,
      y: room.length / 2,
      width: asset?.w || 1,
      depth: asset?.d || 1,
      rotation: 0,
      color: asset?.color || '#000',
      evidenceId: (asset as any)?.isMarker ? `E${objects.filter(o => o.evidenceId).length + 1}` : undefined
    };
    setObjects(prev => [...prev, newObj]);
    setSelectedId(newObj.id);
  };

  const deleteSelected = () => {
    if (selectedId) {
      setObjects(prev => prev.filter(o => o.id !== selectedId));
      setSelectedId(null);
    }
  };

  const updateObject = (id: string, updates: Partial<SceneObject>) => {
    setObjects(prev => prev.map(o => o.id === id ? { ...o, ...updates } : o));
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    // Snap to grid (0.1m increments)
    const snappedX = Math.round((mouseX - dragOffset.x) * 10) / 10;
    const snappedY = Math.round((mouseY - dragOffset.y) * 10) / 10;

    updateObject(selectedId, { x: snappedX, y: snappedY });
  };

  const generateAI = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a forensic sketch JSON for: "${prompt}".
        Output JSON: { room: {width, length}, objects: [{subType, x, y, width, depth, rotation, evidenceId}] }.
        subTypes: Body, Firearm, Blood, Footprints, Wall, Table, Bed, Chair, Door, Window.
        x and y are meters from top-left.`,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              room: {
                type: Type.OBJECT,
                properties: { width: {type: Type.NUMBER}, length: {type: Type.NUMBER} },
                required: ['width', 'length']
              },
              objects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    subType: {type: Type.STRING},
                    x: {type: Type.NUMBER},
                    y: {type: Type.NUMBER},
                    width: {type: Type.NUMBER},
                    depth: {type: Type.NUMBER},
                    rotation: {type: Type.NUMBER},
                    evidenceId: {type: Type.STRING}
                  }
                }
              }
            }
          }
        }
      });
      const data = JSON.parse(response.text);
      setRoom(data.room);
      setObjects(data.objects.map((o:any, i:number) => ({ ...o, id: 'ai-'+i, type: 'Marker' })));
    } catch (e) { console.error(e); }
    finally { setIsGenerating(false); }
  };

  const selectedObj = objects.find(o => o.id === selectedId);

  return (
    <div className="flex flex-col gap-6 h-full max-w-[1600px] mx-auto pb-10">
      {/* Top AI Bar */}
      <div className="bg-slate-900 border border-slate-800 p-6 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
        <div className="relative z-10 flex items-center gap-6">
          <div className="p-4 bg-blue-600/10 rounded-2xl border border-blue-500/20 text-blue-500">
             <Sparkles size={28} className={isGenerating ? 'animate-spin' : ''} />
          </div>
          <div className="flex-1">
             <h2 className="text-white font-bold text-lg mb-2">ForeNova Scene Intelligence</h2>
             <div className="relative">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="E.g., 'A 5x5 room with a body near the south wall and a handgun on the floor...'"
                  className="w-full bg-black/40 border border-white/10 rounded-2xl py-4 pl-6 pr-36 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all placeholder:text-slate-600"
                />
                <button 
                  onClick={generateAI}
                  disabled={isGenerating || !prompt.trim()}
                  className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white px-6 rounded-xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 transition-all shadow-lg"
                >
                  Draft Scene <ArrowRight size={14} />
                </button>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-[700px]">
        {/* Left: Asset Toolbox */}
        <div className="lg:col-span-2 flex flex-col gap-4 overflow-y-auto max-h-[800px] custom-scrollbar">
           <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl space-y-6">
              <div>
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Layers size={14} /> Structural
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.structural.map(a => (
                     // Fix: Pass 'Wall' as the generic structural type for these assets
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Wall')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-blue-600/20 hover:border-blue-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Activity size={14} /> Investigation
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.investigation.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Marker')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-rose-600/20 hover:border-rose-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center text-lg group-hover:scale-125 transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>

              <div>
                <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-4 flex items-center gap-2">
                   <Box size={14} /> Furniture
                </h3>
                <div className="grid grid-cols-1 gap-2">
                   {ASSETS.furniture.map(a => (
                     <button key={a.subType} onClick={() => addObject(a.subType, 'Furniture')} className="flex items-center gap-3 p-3 bg-slate-800 hover:bg-emerald-600/20 hover:border-emerald-500/50 border border-transparent rounded-xl transition-all group">
                        <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-all">{a.icon}</div>
                        <span className="text-[10px] font-bold text-slate-300">{a.label}</span>
                     </button>
                   ))}
                </div>
              </div>
           </div>
        </div>

        {/* Center: Drawing Area */}
        <div className="lg:col-span-7 bg-slate-950 border border-slate-800 rounded-[3rem] overflow-auto shadow-2xl flex flex-col relative group">
           <div className="absolute top-8 left-8 z-10 flex gap-2">
              <div className="bg-blue-600/20 text-blue-400 px-4 py-2 rounded-xl border border-blue-500/20 text-[10px] font-black uppercase tracking-widest">Blueprint Mode</div>
              <div className="bg-slate-900/80 text-slate-500 px-4 py-2 rounded-xl border border-white/5 text-[10px] font-bold uppercase tracking-widest">Grid: 0.5m</div>
           </div>

           <div className="flex-1 flex items-center justify-center p-12">
              <canvas
                ref={canvasRef}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={() => setIsDragging(false)}
                className="shadow-[0_0_100px_rgba(0,0,0,0.5)] cursor-crosshair transition-transform duration-500"
              />
           </div>

           <div className="p-6 bg-slate-900/50 border-t border-white/5 flex justify-between items-center backdrop-blur-md">
              <div className="flex items-center gap-6">
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, width: Math.max(5, r.width-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">W: {room.width}m</span>
                    <button onClick={() => setRoom(r => ({...r, width: r.width+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
                 <div className="flex items-center gap-2">
                    <button onClick={() => setRoom(r => ({...r, length: Math.max(5, r.length-1)}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">-</button>
                    <span className="text-[10px] font-black text-white w-12 text-center">L: {room.length}m</span>
                    <button onClick={() => setRoom(r => ({...r, length: r.length+1}))} className="w-8 h-8 bg-slate-800 rounded-lg hover:bg-slate-700">+</button>
                 </div>
              </div>
              <button 
                onClick={() => {
                  const canvas = canvasRef.current;
                  if (!canvas) return;
                  const link = document.createElement('a');
                  link.download = `Forensic_Sketch_${caseInfo.caseNo}.png`;
                  link.href = canvas.toDataURL();
                  link.click();
                }}
                className="flex items-center gap-2 px-6 py-3 bg-white text-slate-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-50 transition-all shadow-xl"
              >
                <Download size={16} /> Export Blueprint
              </button>
           </div>
        </div>

        {/* Right: Properties Panel */}
        <div className="lg:col-span-3 space-y-4">
           {selectedObj ? (
             <div className="bg-slate-900 border-2 border-blue-500/30 p-8 rounded-[2.5rem] shadow-2xl space-y-8 animate-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
                         <Settings size={20} />
                      </div>
                      <h3 className="font-bold text-white text-lg uppercase tracking-tight">Properties</h3>
                   </div>
