                           <div className="space-y-2">
                              <span className="text-[9px] text-slate-500 uppercase">Y Position (m)</span>
                              <input 
                                type="number" step="0.1"
                                value={selectedObj.y}
                                onChange={(e) => updateObject(selectedObj.id, { y: parseFloat(e.target.value) || 0 })}
                                className="w-full bg-black/40 p-3 rounded-lg border border-white/5 text-xs text-white"
                              />
