import React, { useState, useCallback } from 'react';
import { 
  CheckCircle2, 
  AlertCircle, 
  Trash2, 
  Archive, 
  MapPin, 
  ArrowRight,
  Info,
  Beaker,
  Thermometer,
  ShieldCheck,
  PackageCheck
} from 'lucide-react';
import { EVIDENCE_DATA } from '../constants';
import { EvidenceType } from '../types';

const STEPS = [
  'Tool Selection',
  'Collection Method',
  'Packaging & Labeling',
  'Chain of Custody'
];

const EvidenceSimulator: React.FC = () => {
  const [selectedEvidence, setSelectedEvidence] = useState<EvidenceType | null>(null);
  const [activeTab, setActiveTab] = useState<'collection' | 'preservation'>('collection');
  const [currentStep, setCurrentStep] = useState(0);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const [selectedTools, setSelectedTools] = useState<string[]>([]);

  const playSound = useCallback((type: 'success' | 'error' | 'click') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      const now = ctx.currentTime;
      if (type === 'success') {
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(1320, now + 0.1);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now); osc.stop(now + 0.2);
      } else if (type === 'error') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, now);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.3);
        osc.start(now); osc.stop(now + 0.3);
      } else {
        osc.frequency.setValueAtTime(1500, now);
        gain.gain.setValueAtTime(0.05, now);
        osc.start(now); osc.stop(now + 0.05);
      }
    } catch (e) {}
  }, []);

  const handleEvidenceSelect = (ev: EvidenceType) => {
    playSound('click');
    setSelectedEvidence(ev);
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  const nextStep = () => {
    if (!selectedEvidence) return;

    if (currentStep === 0) {
      // Logic to check if correct tools are selected
      const mandatory = selectedEvidence.toolsNeeded;
      const correctlySelected = mandatory.every(t => selectedTools.includes(t));
      const noExtraIncorrect = selectedTools.every(t => mandatory.includes(t) || !['Generic Box', 'Hammer', 'Plastic Container'].includes(t));

      if (!correctlySelected || selectedTools.length === 0) {
        playSound('error');
        setFeedback({ type: 'error', text: 'Incorrect or insufficient tools selected for this evidence type!' });
        return;
      }
    }

    if (currentStep < STEPS.length - 1) {
      playSound('click');
      setCurrentStep(prev => prev + 1);
      setFeedback(null);
    } else {
      playSound('success');
      setFeedback({ type: 'success', text: 'Training Module Complete! Evidence safely processed.' });
    }
  };

  const resetModule = () => {
    playSound('click');
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  const getIcon = (name: string) => {
    if (name.includes('Blood')) return '🩸';
    if (name.includes('Print')) return '🖐️';
    if (name.includes('DNA') || name.includes('Saliva')) return '🧪';
    if (name.includes('Fiber') || name.includes('Hair')) return '🧵';
    if (name.includes('Firearm') || name.includes('Handgun')) return '🔫';
    if (name.includes('Cartridge') || name.includes('Casing')) return '🐚';
    if (name.includes('Narcotics') || name.includes('Powder')) return '⚖️';
    if (name.includes('Digital') || name.includes('USB')) return '💻';
    return '📦';
  };

  // Build a pool of tools including mandatory ones and distractors
  const getToolPool = () => {
    if (!selectedEvidence) return [];
    const distractors = ['Generic Box', 'Hammer', 'Plastic Container', 'Masking Tape', 'Adhesive Tape'];
    // Merge and shuffle or just filter unique
    const pool = Array.from(new Set([...selectedEvidence.toolsNeeded, ...distractors])).sort();
    return pool;
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto">
      <h1 className="text-3xl font-bold tracking-tight">Evidence Handling Training</h1>

      {/* Mode Tabs */}
      <div className="flex gap-4">
        <button 
          onClick={() => { playSound('click'); setActiveTab('collection'); }}
          className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
            activeTab === 'collection' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'
          }`}
        >
          Collection
        </button>
        <button 
          onClick={() => { playSound('click'); setActiveTab('preservation'); }}
          className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
            activeTab === 'preservation' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'
          }`}
        >
          Preservation & Safety
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 min-h-[600px]">
        {/* Sidebar: Evidence Selection */}
        <div className="lg:col-span-3 bg-[#111827] border border-slate-800 rounded-2xl p-6 overflow-y-auto max-h-[700px]">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6">Select Evidence Type</h3>
          <div className="space-y-3">
            {EVIDENCE_DATA.map(ev => (
              <button
                key={ev.id}
                onClick={() => handleEvidenceSelect(ev)}
                className={`w-full p-4 rounded-xl flex items-center gap-4 transition-all text-left group ${
                  selectedEvidence?.id === ev.id 
                    ? 'bg-blue-600/10 border border-blue-600 text-blue-400' 
                    : 'bg-slate-900 border border-transparent hover:bg-slate-800 text-slate-300'
                }`}
              >
                <span className={`text-2xl group-hover:scale-110 transition-transform`}>{getIcon(ev.name)}</span>
                <span className="text-sm font-bold">{ev.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Main Content Area */}
        <div className="lg:col-span-9 bg-[#111827] border border-slate-800 rounded-2xl p-8 flex flex-col relative overflow-hidden">
          {!selectedEvidence ? (
            <div className="flex-1 flex flex-col items-center justify-center text-center space-y-4 opacity-40">
              <Beaker size={64} className="text-slate-600" />
              <p className="text-lg text-slate-500">Select an evidence type from the left panel to begin your training module.</p>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in fade-in slide-in-from-right-4 duration-300">
              {activeTab === 'collection' ? (
                <div className="space-y-8 flex-1 flex flex-col">
                  {/* Progress Header */}
                  <div className="flex justify-between items-center">
                    <div>
                      <h2 className="text-2xl font-bold text-white">{selectedEvidence.name} Collection</h2>
                      <p className="text-sm text-slate-500 mt-1">Classification: {selectedEvidence.category}</p>
                    </div>
                    <button onClick={resetModule} className="text-xs bg-slate-800 hover:bg-slate-700 px-3 py-1 rounded-lg text-slate-400 flex items-center gap-2">
                      <Trash2 size={12} /> Reset Case
                    </button>
                  </div>

                  {/* Step Indicator */}
                  <div className="flex justify-between px-4">
                    {STEPS.map((step, idx) => (
                      <div key={idx} className="flex flex-col items-center gap-2 relative flex-1">
                        <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs font-bold z-10 transition-all duration-500 ${
                          idx < currentStep ? 'bg-emerald-500 text-white' : idx === currentStep ? 'bg-blue-600 text-white ring-4 ring-blue-600/20' : 'bg-slate-800 text-slate-500'
                        }`}>
                          {idx < currentStep ? <CheckCircle2 size={18} /> : idx + 1}
                        </div>
                        <span className={`text-[10px] font-black uppercase tracking-widest text-center ${idx === currentStep ? 'text-blue-500' : 'text-slate-600'}`}>{step}</span>
                        {idx < STEPS.length - 1 && <div className={`absolute top-5 left-1/2 w-full h-[2px] -z-0 transition-colors duration-500 ${idx < currentStep ? 'bg-emerald-500' : 'bg-slate-800'}`} />}
                      </div>
                    ))}
                  </div>

                  {/* Simulation Body */}
                  <div className="flex-1 bg-slate-900/50 rounded-3xl border border-slate-800 p-8 flex flex-col justify-center items-center text-center">
                    {currentStep === 0 && (
                      <div className="space-y-6 w-full max-w-2xl">
                        <h4 className="text-lg font-bold">Step 1: Required Toolkit Selection</h4>
                        <p className="text-sm text-slate-400">Select only the necessary tools required to process <b>{selectedEvidence.name}</b> according to ISO 17025 standards.</p>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                          {getToolPool().map(tool => (
                            <button
                              key={tool}
                              onClick={() => { playSound('click'); setSelectedTools(prev => prev.includes(tool) ? prev.filter(t => t !== tool) : [...prev, tool]) }}
                              className={`p-4 rounded-xl text-xs font-bold border transition-all ${
                                selectedTools.includes(tool) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:border-slate-500'
                              }`}
                            >
                              {tool}
                            </button>
                          ))}
                        </div>
                      </div>
                    )}

                    {currentStep === 1 && (
                      <div className="space-y-6">
                         <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mx-auto ring-8 ring-blue-600/5">
                            <MapPin size={40} className="text-blue-500 animate-bounce" />
                         </div>
                         <div className="max-w-md">
                            <h4 className="text-lg font-bold">Step 2: Methodical Extraction Phase</h4>
                            <p className="text-sm text-slate-400 leading-relaxed mt-2 italic">
                               "Carefully isolating the area. Utilizing {selectedTools.join(', ')} to secure the primary specimen. Ensuring no cross-contamination between exhibits..."
                            </p>
                         </div>
                      </div>
                    )}

                    {currentStep === 2 && (
                      <div className="space-y-6 w-full max-w-lg">
                        <h4 className="text-lg font-bold">Step 3: Packaging & Seal Integrity</h4>
                        <div className="bg-slate-800 p-8 rounded-[2rem] border-2 border-dashed border-slate-700 text-left space-y-6">
                           <div className="flex items-center gap-3">
                              <PackageCheck className="text-emerald-500" />
                              <span className="text-sm font-black uppercase tracking-widest text-emerald-400">Required Packaging</span>
                           </div>
                           <p className="text-sm font-mono text-slate-100 bg-black/50 p-6 rounded-2xl border border-white/5">
                              SYSTEM RECOMMENDATION: {selectedEvidence.packaging.toUpperCase()}
                           </p>
                           <div className="p-4 bg-amber-500/10 rounded-xl border border-amber-500/20 text-[10px] text-amber-300 font-bold uppercase tracking-wider leading-relaxed">
                              Warning: Never use plastic containers for biological samples unless specified, as trapped moisture promotes fungal growth.
                           </div>
                        </div>
                      </div>
                    )}

                    {currentStep === 3 && (
                      <div className="space-y-6 w-full max-w-lg">
                         <div className="bg-white/5 border border-white/10 p-10 rounded-[2.5rem] relative overflow-hidden shadow-2xl">
                            <div className="absolute top-0 right-0 p-3 bg-blue-600 text-[9px] font-black uppercase rotate-45 translate-x-6 -translate-y-2 shadow-lg">AUTHENTICATED</div>
                            <div className="flex items-center gap-3 mb-8">
                               <div className="w-10 h-10 bg-slate-800 rounded-xl flex items-center justify-center"><ShieldCheck size={20} className="text-blue-500"/></div>
                               <h4 className="font-serif text-2xl italic">Chain of Custody Record</h4>
                            </div>
                            <div className="space-y-4 font-mono text-[11px] text-left opacity-80 border-t border-white/10 pt-6">
                               <div className="flex justify-between"><span className="text-slate-500">EXHIBIT ID:</span> <span className="text-blue-400">#EV-{selectedEvidence.id}-SEC</span></div>
                               <div className="flex justify-between"><span className="text-slate-500">DESCRIPTION:</span> <span className="text-white">{selectedEvidence.name.toUpperCase()}</span></div>
                               <div className="flex justify-between"><span className="text-slate-500">RECOVERED BY:</span> <span className="text-white">FORENOVA TRAINEE</span></div>
                               <div className="flex justify-between"><span className="text-slate-500">TIMESTAMP:</span> <span className="text-white">{new Date().toLocaleString()}</span></div>
                            </div>
                         </div>
                      </div>
                    )}

                    {feedback && (
                      <div className={`mt-8 w-full p-6 rounded-2xl flex items-center gap-4 border animate-in slide-in-from-bottom-2 ${
                        feedback.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400 shadow-lg shadow-emerald-500/5' : 'bg-rose-500/10 border-rose-500/30 text-rose-400 shadow-lg shadow-rose-500/5'
                      }`}>
                        {feedback.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
                        <p className="text-sm font-bold uppercase tracking-tight">{feedback.text}</p>
                      </div>
                    )}
                  </div>

                  <button 
                    onClick={nextStep}
                    className="mt-auto w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 transition-all shadow-xl shadow-blue-500/20 active:scale-[0.98]"
                  >
                    {currentStep === STEPS.length - 1 ? 'Archive & Finalize Training' : 'Proceed to Next Phase'}
                    <ArrowRight size={20} />
                  </button>
                </div>
              ) : (
                <div className="space-y-8 animate-in fade-in duration-500">
                  <div className="flex justify-between items-start border-b border-slate-800 pb-6">
                    <div>
                      <h2 className="text-3xl font-bold text-white tracking-tight">{selectedEvidence.name} Preservation</h2>
                      <p className="text-sm text-slate-500 mt-1 uppercase font-bold tracking-widest">Protocol: Scientific Preservation & Storage</p>
                    </div>
                    <div className="p-4 bg-amber-500/10 text-amber-500 rounded-2xl border border-amber-500/20">
                       <ShieldCheck size={28} />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                     <div className="bg-slate-900/50 p-8 rounded-[2.5rem] border border-slate-800 space-y-6 hover:border-blue-500/30 transition-all group">
                        <div className="flex items-center gap-3 text-blue-400">
                           <Thermometer size={24} />
                           <h4 className="text-[10px] font-black uppercase tracking-widest">Temperature Compliance</h4>
                        </div>
                        <p className="text-4xl font-black text-white group-hover:scale-110 origin-left transition-transform">{selectedEvidence.temperature}</p>
                        <p className="text-xs text-slate-500 leading-relaxed italic">Maintaining this thermal range is critical to prevent molecular degradation of the sample.</p>
                     </div>

                     <div className="bg-slate-900/50 p-8 rounded-[2.5rem] border border-slate-800 space-y-6 hover:border-emerald-500/30 transition-all group">
                        <div className="flex items-center gap-3 text-emerald-400">
